package controle.api.back_end;

import controle.api.back_end.config.DesktopApp;
import javafx.application.Application;
import org.h2.tools.Server;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.boot.autoconfigure.domain.EntityScan;
import org.springframework.context.annotation.Bean;
import java.sql.SQLException;

@SpringBootApplication
@EntityScan(basePackages = "controle.api.back_end.model")
public class BackEndApplication {

	public static void main(String[] args) {
		new Thread(() -> SpringApplication.run(BackEndApplication.class)).start();
		Application.launch(DesktopApp.class, args);
	}

	@Bean(initMethod = "start", destroyMethod = "stop")
	@ConditionalOnProperty(name = "h2.tcp.enabled", havingValue = "true", matchIfMissing = true)
	public Server h2Server() throws SQLException {
		return Server.createTcpServer("-tcp", "-tcpAllowOthers", "-tcpPort", "9092");
	}

}

package controle.api.back_end;

import controle.api.back_end.config.DesktopApp;
import javafx.application.Application;
import org.h2.tools.Server;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.boot.autoconfigure.domain.EntityScan;
import org.springframework.context.annotation.Bean;
import org.springframework.scheduling.annotation.EnableScheduling;
import java.sql.SQLException;

@SpringBootApplication
@EntityScan(basePackages = "controle.api.back_end.model")
@EnableScheduling
public class BackEndApplication {

	public static void main(String[] args) {
		new Thread(() -> SpringApplication.run(BackEndApplication.class)).start();
		Application.launch(DesktopApp.class, args);
	}

	@Bean(initMethod = "start", destroyMethod = "stop")
	@ConditionalOnProperty(name = "h2.tcp.enabled", havingValue = "true", matchIfMissing = true)
	public Server h2Server() throws SQLException {
		return Server.createTcpServer("-tcp", "-tcpAllowOthers", "-tcpPort", "9092");
	}

}

package controle.api.back_end.controller;

import controle.api.back_end.dto.poupanca.in.CaixinhaCreateDTO;
import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.service.CaixinhaService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.math.BigDecimal;
import java.util.List;
import java.util.UUID;

@CrossOrigin
@RestController
@RequestMapping("/caixinhas")
@Tag(name = "Caixinhas / Poupança",
     description = "Gerenciamento de caixinhas de poupança com metas, rendimentos (CDI/SELIC/Prefixado) " +
                   "e projeções financeiras. Suporta metas simples e compartilhadas entre múltiplas instituições.")
public class CaixinhaController {

    private final CaixinhaService caixinhaService;

    public CaixinhaController(CaixinhaService caixinhaService) {
        this.caixinhaService = caixinhaService;
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    @PostMapping
    @Operation(summary = "Criar uma nova caixinha",
               description = """
                       Cria uma caixinha de poupança com meta, prazo e rendimento configuráveis.

                       **Tipos de rendimento:**
                       - `CDI` – percentual do CDI (ex.: 100% ou 110%). Informe `taxaReferenciaAtual` (CDI atual em % a.a.) e `percentualRendimento`.
                       - `SELIC` – percentual da SELIC. Informe `taxaReferenciaAtual` e `percentualRendimento`.
                       - `POUPANCA` – rendimento tradicional (70% da SELIC). Informe `taxaReferenciaAtual`.
                       - `PREFIXADO` – taxa fixa anual. Informe `taxaAnualPersonalizada` (ex.: 12.5 para 12,5% a.a.).
                       - `PERSONALIZADO` – taxa definida livremente. Informe `taxaAnualPersonalizada`.

                       **Meta compartilhada:** informe `isCompartilhada=true` e 2 ou mais `instituicaoUsuarioIds`.
                       A API somará os aportes de todas as instituições para calcular o saldo total.
                       """)
    @ApiResponses({
            @ApiResponse(responseCode = "201", description = "Caixinha criada com sucesso.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Dados inválidos.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário ou instituição não encontrados.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> criar(@Valid @RequestBody CaixinhaCreateDTO dto) {
        return ResponseEntity.status(201).body(caixinhaService.criar(dto));
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    @GetMapping("/usuarios/{user_id}")
    @Operation(summary = "Listar todas as caixinhas do usuário",
               description = "Retorna todas as caixinhas (ativas e encerradas) com saldo atual, " +
                             "projeções e aporte sugerido calculados em tempo real.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinhas encontradas.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "204", description = "Nenhuma caixinha cadastrada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<List<CaixinhaResponseDTO>> listarPorUsuario(@PathVariable UUID user_id) {
        List<CaixinhaResponseDTO> lista = caixinhaService.listarPorUsuario(user_id);
        return lista.isEmpty() ? ResponseEntity.noContent().build() : ResponseEntity.ok(lista);
    }

    @GetMapping("/ativas/usuarios/{user_id}")
    @Operation(summary = "Listar caixinhas ativas do usuário",
               description = "Retorna apenas as caixinhas em andamento (não encerradas).")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinhas encontradas.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "204", description = "Nenhuma caixinha ativa.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<List<CaixinhaResponseDTO>> listarAtivasPorUsuario(@PathVariable UUID user_id) {
        List<CaixinhaResponseDTO> lista = caixinhaService.listarAtivasPorUsuario(user_id);
        return lista.isEmpty() ? ResponseEntity.noContent().build() : ResponseEntity.ok(lista);
    }

    @GetMapping("/{caixinha_id}")
    @Operation(summary = "Buscar uma caixinha por ID",
               description = "Retorna os dados completos de uma caixinha com todos os cálculos atualizados.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha encontrada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> buscarPorId(@PathVariable UUID caixinha_id) {
        return ResponseEntity.ok(caixinhaService.buscarPorId(caixinha_id));
    }

    @GetMapping("/resumo/usuarios/{user_id}")
    @Operation(summary = "Total acumulado em poupança",
               description = "Soma o saldo atual de todas as caixinhas ativas do usuário. " +
                             "Útil para exibir um número único de 'total guardado' na tela inicial.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Total calculado.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(example = "4750.00"))),
            @ApiResponse(responseCode = "404", description = "Usuário não encontrado.", content = @Content)
    })
    public ResponseEntity<BigDecimal> resumoTotal(@PathVariable UUID user_id) {
        return ResponseEntity.ok(caixinhaService.resumoTotalPoupanca(user_id));
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    @PutMapping("/{caixinha_id}")
    @Operation(summary = "Editar uma caixinha",
               description = "Atualiza nome, descrição, meta, prazo e/ou configuração de rendimento. " +
                             "Os aportes já realizados não são afetados.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha atualizada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> editar(@PathVariable UUID caixinha_id,
                                                       @RequestBody CaixinhaCreateDTO dto) {
        return ResponseEntity.ok(caixinhaService.editar(caixinha_id, dto));
    }

    @PatchMapping("/{caixinha_id}/encerrar")
    @Operation(summary = "Encerrar uma caixinha",
               description = "Marca a caixinha como encerrada (meta atingida ou cancelada pelo usuário). " +
                             "Os dados e histórico de aportes são mantidos.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Caixinha encerrada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> encerrar(@PathVariable UUID caixinha_id) {
        return ResponseEntity.ok(caixinhaService.encerrar(caixinha_id));
    }

    @PostMapping("/{caixinha_id}/instituicoes/{inst_id}")
    @Operation(summary = "Adicionar instituição a uma caixinha compartilhada",
               description = "Vincula uma nova instituição à caixinha, habilitando a meta compartilhada. " +
                             "O saldo total passa a somar os aportes de todas as instituições vinculadas.")
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Instituição adicionada.",
                    content = @Content(mediaType = "application/json",
                            schema = @Schema(implementation = CaixinhaResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Instituição já vinculada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Caixinha ou instituição não encontradas.", content = @Content)
    })
    public ResponseEntity<CaixinhaResponseDTO> adicionarInstituicao(@PathVariable UUID caixinha_id,
                                                                      @PathVariable Integer inst_id) {
        return ResponseEntity.ok(caixinhaService.adicionarInstituicao(caixinha_id, inst_id));
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    @DeleteMapping("/{caixinha_id}")
    @Operation(summary = "Deletar uma caixinha",
               description = "Remove permanentemente a caixinha e seus vínculos com instituições. " +
                             "Os aportes registrados como EventoFinanceiro NÃO são deletados.")
    @ApiResponses({
            @ApiResponse(responseCode = "204", description = "Caixinha deletada.", content = @Content),
            @ApiResponse(responseCode = "404", description = "Caixinha não encontrada.", content = @Content)
    })
    public ResponseEntity<Void> deletar(@PathVariable UUID caixinha_id) {
        caixinhaService.deletar(caixinha_id);
        return ResponseEntity.noContent().build();
    }
}

package controle.api.back_end.dto.configuracoes.in;

import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.Positive;

import java.util.List;

public class ConfiguracaoEditDTO {
    @Positive
    @Schema(example = "01", description="Representa o inicio do mês fiscal do usuário")
    private Integer inicioMesFiscal;

    @Positive
    @Schema(example = "1150.0", description="Representa limite total que o usuário deseja gastar por mês, sem especificar o quanto vai ser por instituição")
    private Double limiteDesejadoMensal;

    private List<LimiteInstituicaoEditDTO> limitesInstituicao;
    private List<LimiteCategoriaEditDTO> limitesCategoria;

    public static class LimiteInstituicaoEditDTO{
        private Integer instituicaoId;
        private Double valor;

        public Integer getInstituicaoId() {
            return instituicaoId;
        }

        public void setInstituicaoId(Integer instituicaoId) {
            this.instituicaoId = instituicaoId;
        }

        public Double getValor() {
            return valor;
        }

        public void setValor(Double valor) {
            this.valor = valor;
        }
    }

    public static class LimiteCategoriaEditDTO{
        private Integer categoriaId;
        private Double valor;

        public Integer getCategoriaId() {
            return categoriaId;
        }

        public void setCategoriaId(Integer categoriaId) {
            this.categoriaId = categoriaId;
        }

        public Double getValor() {
            return valor;
        }

        public void setValor(Double valor) {
            this.valor = valor;
        }
    }

    public Integer getInicioMesFiscal() {
        return inicioMesFiscal;
    }

    public void setInicioMesFiscal(Integer inicioMesFiscal) {
        this.inicioMesFiscal = inicioMesFiscal;
    }

    public Double getLimiteDesejadoMensal() {
        return limiteDesejadoMensal;
    }

    public void setLimiteDesejadoMensal(Double limiteDesejadoMensal) {
        this.limiteDesejadoMensal = limiteDesejadoMensal;
    }

    public List<LimiteInstituicaoEditDTO> getLimitesInstituicao() {
        return limitesInstituicao;
    }

    public void setLimitesInstituicao(List<LimiteInstituicaoEditDTO> limitesInstituicao) {
        this.limitesInstituicao = limitesInstituicao;
    }

    public List<LimiteCategoriaEditDTO> getLimitesCategoria() {
        return limitesCategoria;
    }

    public void setLimitesCategoria(List<LimiteCategoriaEditDTO> limitesCategoria) {
        this.limitesCategoria = limitesCategoria;
    }
}

package controle.api.back_end.dto.configuracoes.in;

import controle.api.back_end.model.configuracoes.TipoAlertaEmail;
import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.Max;
import jakarta.validation.constraints.Min;
import jakarta.validation.constraints.Positive;

import java.util.List;
import java.util.Set;

public class ConfiguracaoEditDTO {

    @Positive
    @Schema(example = "01", description = "Inicio do mes fiscal do usuario")
    private Integer inicioMesFiscal;

    @Positive
    @Schema(example = "1150.0", description = "Limite total de gastos mensais")
    private Double limiteDesejadoMensal;

    private List<LimiteInstituicaoEditDTO> limitesInstituicao;
    private List<LimiteCategoriaEditDTO> limitesCategoria;

    @Schema(description = "Alertas de e-mail ativos. Opcoes: ANIVERSARIO, ALERTA_LIMITE_MENSAL, ALERTA_META_POUPANCA, RELATORIO_MENSAL, LEMBRETE_APORTE")
    private Set<TipoAlertaEmail> alertasEmailAtivos;

    @Min(1) @Max(100)
    @Schema(description = "Percentual do limite mensal que dispara alerta. Padrao: 80", example = "80")
    private Integer percentualAlertaGasto;

    @Min(1) @Max(100)
    @Schema(description = "Percentual da meta de poupanca que dispara alerta. Padrao: 90", example = "90")
    private Integer percentualAlertaMeta;

    public Integer getInicioMesFiscal() { return inicioMesFiscal; }
    public void setInicioMesFiscal(Integer inicioMesFiscal) { this.inicioMesFiscal = inicioMesFiscal; }

    public Double getLimiteDesejadoMensal() { return limiteDesejadoMensal; }
    public void setLimiteDesejadoMensal(Double limiteDesejadoMensal) { this.limiteDesejadoMensal = limiteDesejadoMensal; }

    public List<LimiteInstituicaoEditDTO> getLimitesInstituicao() { return limitesInstituicao; }
    public void setLimitesInstituicao(List<LimiteInstituicaoEditDTO> limitesInstituicao) { this.limitesInstituicao = limitesInstituicao; }

    public List<LimiteCategoriaEditDTO> getLimitesCategoria() { return limitesCategoria; }
    public void setLimitesCategoria(List<LimiteCategoriaEditDTO> limitesCategoria) { this.limitesCategoria = limitesCategoria; }

    public Set<TipoAlertaEmail> getAlertasEmailAtivos() { return alertasEmailAtivos; }
    public void setAlertasEmailAtivos(Set<TipoAlertaEmail> alertasEmailAtivos) { this.alertasEmailAtivos = alertasEmailAtivos; }

    public Integer getPercentualAlertaGasto() { return percentualAlertaGasto; }
    public void setPercentualAlertaGasto(Integer percentualAlertaGasto) { this.percentualAlertaGasto = percentualAlertaGasto; }

    public Integer getPercentualAlertaMeta() { return percentualAlertaMeta; }
    public void setPercentualAlertaMeta(Integer percentualAlertaMeta) { this.percentualAlertaMeta = percentualAlertaMeta; }

    public static class LimiteInstituicaoEditDTO {
        private Integer instituicaoId;
        private Double valor;
        public Integer getInstituicaoId() { return instituicaoId; }
        public void setInstituicaoId(Integer instituicaoId) { this.instituicaoId = instituicaoId; }
        public Double getValor() { return valor; }
        public void setValor(Double valor) { this.valor = valor; }
    }

    public static class LimiteCategoriaEditDTO {
        private Integer categoriaId;
        private Double valor;
        public Integer getCategoriaId() { return categoriaId; }
        public void setCategoriaId(Integer categoriaId) { this.categoriaId = categoriaId; }
        public Double getValor() { return valor; }
        public void setValor(Double valor) { this.valor = valor; }
    }
}

package controle.api.back_end.dto.configuracoes.mapper;

import controle.api.back_end.dto.configuracoes.in.ConfiguracaoEditDTO;
import controle.api.back_end.dto.configuracoes.in.ConfiguracoesCreateDTO;
import controle.api.back_end.dto.configuracoes.out.ConfiguracaoUsuarioResponseDTO;
import controle.api.back_end.dto.configuracoes.out.ConfiguracoesResponsesDTO;
import controle.api.back_end.dto.configuracoes.out.LimitePorCategoriaResponseDto;
import controle.api.back_end.dto.configuracoes.out.LimitePorInstituicaoResponseDto;
import controle.api.back_end.model.configuracoes.Configuracoes;
import controle.api.back_end.model.configuracoes.LimitePorCategoria;
import controle.api.back_end.model.configuracoes.LimitePorInstituicao;
import controle.api.back_end.model.usuario.Usuario;
import jakarta.validation.Valid;

import java.util.ArrayList;
import java.util.List;

public class ConfiguracoesMapper {

    public static ConfiguracoesResponsesDTO toDto(Configuracoes model) {
        if(model == null){
            return null;
        }

        ConfiguracoesResponsesDTO dto = new ConfiguracoesResponsesDTO();

        dto.setId(model.getId());
        dto.setInicioMesFiscal(model.getInicioMesFiscal());
        dto.setLimiteDesejadoMensal(model.getLimiteDesejadoMensal());
        dto.setUltimaAtualizacao(model.getUltimaAtualizacao());

        return dto;
    }
    public static List<ConfiguracoesResponsesDTO> toDto(List<Configuracoes> models){
        return models.stream()
                .map(ConfiguracoesMapper::toDto)
                .toList();
    }

    public static ConfiguracaoUsuarioResponseDTO toDtoUser(Configuracoes model) {
        if (model == null) {
            return null;
        }

        Usuario modelUser = model.getUsuario();
        ConfiguracaoUsuarioResponseDTO dto = new ConfiguracaoUsuarioResponseDTO();

        // USUÁRIO
        ConfiguracaoUsuarioResponseDTO.ConfiguracaoUsuarioDTO dtoUser = new ConfiguracaoUsuarioResponseDTO.ConfiguracaoUsuarioDTO();
        dtoUser.setId(modelUser.getId());
        dtoUser.setNome(modelUser.getNome());
        dtoUser.setSobrenome(modelUser.getSobrenome());
        dtoUser.setEmail(modelUser.getEmail());

        dto.setId(model.getId());
        dto.setUsuario(dtoUser);
        dto.setInicioMesFiscal(model.getInicioMesFiscal());
        dto.setLimiteDesejadoMensal(model.getLimiteDesejadoMensal());
        dto.setUltimaAtualizacao(model.getUltimaAtualizacao());

        // LIMITE POR CATEGORIA (lista)
        List<LimitePorCategoriaResponseDto> limitesCategoriaDTO = new ArrayList<>();
        if (model.getLimitePorCategoria() != null) {
            for (LimitePorCategoria limite : model.getLimitePorCategoria()) {
                LimitePorCategoriaResponseDto limiteCategoriaDTO = new LimitePorCategoriaResponseDto();

                LimitePorCategoriaResponseDto.CategoriaDTO categoriaDTO = new LimitePorCategoriaResponseDto.CategoriaDTO();


                categoriaDTO.setId(limite.getCategoriaUsuario().getCategoria().getId());
                categoriaDTO.setTitulo(limite.getCategoriaUsuario().getCategoria().getTitulo());

                limiteCategoriaDTO.setCategoria(categoriaDTO);
                limiteCategoriaDTO.setLimiteDesejado(limite.getLimiteDesejado());
                limiteCategoriaDTO.setId(limite.getId());
                limitesCategoriaDTO.add(limiteCategoriaDTO);
            }
        }
        dto.setLimitePorCategoria(limitesCategoriaDTO);

        // LIMITE POR INSTITUIÇÃO (lista)
        List<LimitePorInstituicaoResponseDto> limitesInstituicaoDTO = new ArrayList<>();
        if (model.getLimitePorInstituicao() != null) {
            for (LimitePorInstituicao limite : model.getLimitePorInstituicao()) {
                LimitePorInstituicaoResponseDto limiteInstituicaoDTO =
                        new LimitePorInstituicaoResponseDto();

                LimitePorInstituicaoResponseDto.InstituicaoDTO instituicaoDTO =
                        new LimitePorInstituicaoResponseDto.InstituicaoDTO();


                instituicaoDTO.setId(limite.getInstituicaoUsuario().getInstituicao().getId());
                instituicaoDTO.setNome(limite.getInstituicaoUsuario().getInstituicao().getNome());


                limiteInstituicaoDTO.setLimiteDesejado(limite.getLimiteDesejado());
                limiteInstituicaoDTO.setInstituicao(instituicaoDTO);
                limiteInstituicaoDTO.setId(limite.getId());
                limitesInstituicaoDTO.add(limiteInstituicaoDTO);
            }
        }
        dto.setLimiteInstituicao(limitesInstituicaoDTO);

        return dto;
    }

    public static List<ConfiguracaoUsuarioResponseDTO> toDtoUser(List<Configuracoes> models){
        return models.stream()
                .map(ConfiguracoesMapper::toDtoUser)
                .toList();
    }

    public static Configuracoes toEntity(@Valid ConfiguracoesCreateDTO dto) {
        if(dto==null){
            return null;
        }

        Configuracoes entity = new Configuracoes();

        Usuario user = new Usuario();
        user.setId(dto.getFkUsuario());

        entity.setInicioMesFiscal(dto.getInicioMesFiscal());
        entity.setLimiteDesejadoMensal(dto.getLimiteDesejadoMensal());
        entity.setUsuario(user);
        return entity;
    }

    public static Configuracoes toEntity(@Valid ConfiguracaoEditDTO dto) {
        if (dto == null){
            return null;
        }

        Configuracoes entity = new Configuracoes();
        if (dto.getInicioMesFiscal()!= null){
            entity.setInicioMesFiscal(dto.getInicioMesFiscal());
        }

        if(dto.getLimiteDesejadoMensal()!= null){
            entity.setLimiteDesejadoMensal(dto.getLimiteDesejadoMensal());
        }

        return entity;
    }
}

package controle.api.back_end.dto.configuracoes.mapper;

import controle.api.back_end.dto.configuracoes.in.ConfiguracaoEditDTO;
import controle.api.back_end.dto.configuracoes.in.ConfiguracoesCreateDTO;
import controle.api.back_end.dto.configuracoes.out.ConfiguracaoUsuarioResponseDTO;
import controle.api.back_end.dto.configuracoes.out.ConfiguracoesResponsesDTO;
import controle.api.back_end.dto.configuracoes.out.LimitePorCategoriaResponseDto;
import controle.api.back_end.dto.configuracoes.out.LimitePorInstituicaoResponseDto;
import controle.api.back_end.model.configuracoes.Configuracoes;
import controle.api.back_end.model.configuracoes.LimitePorCategoria;
import controle.api.back_end.model.configuracoes.LimitePorInstituicao;
import controle.api.back_end.model.usuario.Usuario;
import jakarta.validation.Valid;

import java.util.ArrayList;
import java.util.List;

public class ConfiguracoesMapper {

    public static ConfiguracoesResponsesDTO toDto(Configuracoes model) {
        if(model == null){
