    public Set<TipoAlertaEmail> getAlertasEmailAtivos() { return alertasEmailAtivos; }
    public void setAlertasEmailAtivos(Set<TipoAlertaEmail> alertasEmailAtivos) { this.alertasEmailAtivos = alertasEmailAtivos; }

