package controle.api.back_end.service;

import controle.api.back_end.dto.poupanca.in.CaixinhaCreateDTO;
import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.instituicao.InstituicaoUsuario;
import controle.api.back_end.model.poupanca.Caixinha;
import controle.api.back_end.model.poupanca.CaixinhaInstituicao;
import controle.api.back_end.model.poupanca.TipoRendimento;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.instituicao.InstituicaoUsuarioRepository;
import controle.api.back_end.repository.poupanca.CaixinhaInstituicaoRepository;
import controle.api.back_end.repository.poupanca.CaixinhaRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import controle.api.back_end.model.configuracoes.TipoAlertaEmail;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.MathContext;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.time.Period;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Serviço responsável pelo ciclo de vida das caixinhas de poupança e
 * todos os cálculos financeiros associados.
 *
 * <h3>Cálculos implementados</h3>
 * <ul>
 *   <li><b>Taxa mensal efetiva</b>: convertida da taxa anual para composto mensal.</li>
 *   <li><b>Montante projetado sem aportes</b>: VF = VP × (1 + r)^n</li>
 *   <li><b>Aporte mensal sugerido (PMT)</b>:
 *       PMT = [VF − VP×(1+r)^n] × r / [(1+r)^n − 1]
 *       <br>Se r = 0: PMT = (VF − VP) / n</li>
 *   <li><b>Montante projetado com aportes</b>:
 *       VF = VP×(1+r)^n + PMT × [(1+r)^n − 1] / r</li>
 * </ul>
 */
@Service
@Transactional
public class CaixinhaService {

    private static final Logger log = LoggerFactory.getLogger(CaixinhaService.class);

    private final CaixinhaRepository caixinhaRepository;
    private final CaixinhaInstituicaoRepository caixinhaInstituicaoRepository;
    private final UsuarioRepository usuarioRepository;
    private final InstituicaoUsuarioRepository instituicaoUsuarioRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final ConfiguracoesRepository configuracoesRepository;
    private final EmailService emailService;

    public CaixinhaService(CaixinhaRepository caixinhaRepository,
                           CaixinhaInstituicaoRepository caixinhaInstituicaoRepository,
                           UsuarioRepository usuarioRepository,
                           InstituicaoUsuarioRepository instituicaoUsuarioRepository,
                           EventoFinanceiroRepository eventoFinanceiroRepository,
                           ConfiguracoesRepository configuracoesRepository,
                           EmailService emailService) {
        this.caixinhaRepository              = caixinhaRepository;
        this.caixinhaInstituicaoRepository   = caixinhaInstituicaoRepository;
        this.usuarioRepository               = usuarioRepository;
        this.instituicaoUsuarioRepository    = instituicaoUsuarioRepository;
        this.eventoFinanceiroRepository      = eventoFinanceiroRepository;
        this.configuracoesRepository         = configuracoesRepository;
        this.emailService                    = emailService;
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    /** Cria uma nova caixinha e vincula as instituições informadas. */
    public CaixinhaResponseDTO criar(CaixinhaCreateDTO dto) {
        usuarioRepository.findById(dto.getUsuarioId())
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Usuário de id: %s não encontrado.".formatted(dto.getUsuarioId())));

        Caixinha caixinha = new Caixinha();
        caixinha.setUsuario(usuarioRepository.getReferenceById(dto.getUsuarioId()));
        caixinha.setNome(dto.getNome());
        caixinha.setDescricao(dto.getDescricao());
        caixinha.setValorMeta(dto.getValorMeta());
        caixinha.setDataPrazo(dto.getDataPrazo());
        caixinha.setTipoRendimento(dto.getTipoRendimento());
        caixinha.setPercentualRendimento(dto.getPercentualRendimento());
        caixinha.setTaxaAnualPersonalizada(dto.getTaxaAnualPersonalizada());
        caixinha.setTaxaReferenciaAtual(dto.getTaxaReferenciaAtual());
        caixinha.setIsCompartilhada(dto.getIsCompartilhada() != null && dto.getIsCompartilhada());
        caixinha.setIsAtiva(true);
        caixinha.setDataCriacao(LocalDate.now());

        Caixinha salva = caixinhaRepository.save(caixinha);

        // Vincula as instituicoes
        for (Integer instId : dto.getInstituicaoUsuarioIds()) {
            InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                    .orElseThrow(() -> new EntidadeNaoEncontradaException(
                            "InstituicaoUsuario de id: %d nao encontrada.".formatted(instId)));
            CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
            vinculo.setCaixinha(salva);
            vinculo.setInstituicaoUsuario(inst);
            caixinhaInstituicaoRepository.save(vinculo);
        }

        CaixinhaResponseDTO resultado = calcularEMontar(salva);
        verificarEEnviarAlertaMeta(salva, resultado);
        return resultado;
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    /** Retorna todas as caixinhas (ativas e inativas) do usuário com cálculos. */
    @Transactional(readOnly = true)
    public List<CaixinhaResponseDTO> listarPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_Id(usuarioId).stream()
                .map(this::calcularEMontar)
                .toList();
    }

    /** Retorna apenas as caixinhas ativas do usuário. */
    @Transactional(readOnly = true)
    public List<CaixinhaResponseDTO> listarAtivasPorUsuario(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId).stream()
                .map(this::calcularEMontar)
                .toList();
    }

    /** Retorna uma caixinha específica com todos os cálculos. */
    @Transactional(readOnly = true)
    public CaixinhaResponseDTO buscarPorId(UUID caixinhaId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        return calcularEMontar(caixinha);
    }

    /** Resumo total de poupança do usuário (soma de todas as caixinhas ativas). */
    @Transactional(readOnly = true)
    public BigDecimal resumoTotalPoupanca(UUID usuarioId) {
        validarUsuario(usuarioId);
        return caixinhaRepository.findAllByUsuario_IdAndIsAtivaTrue(usuarioId).stream()
                .map(c -> eventoFinanceiroRepository.sumValorByCaixinha(c.getId()))
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    /** Edita os dados configuráveis de uma caixinha (não afeta aportes existentes). */
    public CaixinhaResponseDTO editar(UUID caixinhaId, CaixinhaCreateDTO dto) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));

        if (dto.getNome() != null) caixinha.setNome(dto.getNome());
        if (dto.getDescricao() != null) caixinha.setDescricao(dto.getDescricao());
        if (dto.getValorMeta() != null) caixinha.setValorMeta(dto.getValorMeta());
        if (dto.getDataPrazo() != null) caixinha.setDataPrazo(dto.getDataPrazo());
        if (dto.getTipoRendimento() != null) caixinha.setTipoRendimento(dto.getTipoRendimento());
        if (dto.getPercentualRendimento() != null) caixinha.setPercentualRendimento(dto.getPercentualRendimento());
        if (dto.getTaxaAnualPersonalizada() != null) caixinha.setTaxaAnualPersonalizada(dto.getTaxaAnualPersonalizada());
        if (dto.getTaxaReferenciaAtual() != null) caixinha.setTaxaReferenciaAtual(dto.getTaxaReferenciaAtual());

        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    /** Encerra uma caixinha (marca como inativa). */
    public CaixinhaResponseDTO encerrar(UUID caixinhaId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        caixinha.setIsAtiva(false);
        caixinha.setDataEncerramento(LocalDate.now());
        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    /** Vincula uma nova instituição a uma caixinha compartilhada. */
    public CaixinhaResponseDTO adicionarInstituicao(UUID caixinhaId, Integer instId) {
        Caixinha caixinha = caixinhaRepository.findById(caixinhaId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Caixinha de id: %s não encontrada.".formatted(caixinhaId)));
        if (caixinhaInstituicaoRepository.existsByCaixinha_IdAndInstituicaoUsuario_Id(caixinhaId, instId)) {
            throw new IllegalArgumentException("Instituição já vinculada a esta caixinha.");
        }
        InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(instId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "InstituicaoUsuario de id: %d não encontrada.".formatted(instId)));
        CaixinhaInstituicao vinculo = new CaixinhaInstituicao();
        vinculo.setCaixinha(caixinha);
        vinculo.setInstituicaoUsuario(inst);
        caixinhaInstituicaoRepository.save(vinculo);
        caixinha.setIsCompartilhada(true);
        return calcularEMontar(caixinhaRepository.save(caixinha));
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    public void deletar(UUID caixinhaId) {
        if (!caixinhaRepository.existsById(caixinhaId)) {
            throw new EntidadeNaoEncontradaException(
                    "Caixinha de id: %s não encontrada.".formatted(caixinhaId));
        }
        caixinhaRepository.deleteById(caixinhaId);
    }

    // =========================================================================
    // CÁLCULOS FINANCEIROS (acesso package para uso no EmailService)
    // =========================================================================

    /**
     * Monta o DTO de resposta completo com todos os cálculos aplicados.
     */
    CaixinhaResponseDTO calcularEMontar(Caixinha c) {
        CaixinhaResponseDTO dto = new CaixinhaResponseDTO();

        // Dados básicos
        dto.setId(c.getId());
        dto.setNome(c.getNome());
        dto.setDescricao(c.getDescricao());
        dto.setIsAtiva(c.getIsAtiva());
        dto.setIsCompartilhada(c.getIsCompartilhada());
        dto.setDataCriacao(c.getDataCriacao());
        dto.setDataEncerramento(c.getDataEncerramento());
        dto.setValorMeta(c.getValorMeta());
        dto.setDataPrazo(c.getDataPrazo());
        dto.setTipoRendimento(c.getTipoRendimento());
        dto.setPercentualRendimento(c.getPercentualRendimento());
        dto.setTaxaAnualPersonalizada(c.getTaxaAnualPersonalizada());
        dto.setTaxaReferenciaAtual(c.getTaxaReferenciaAtual());

        // Valor atual = soma dos aportes registrados
        BigDecimal valorAtual = eventoFinanceiroRepository.sumValorByCaixinha(c.getId());
        dto.setValorAtual(valorAtual);

        // Progresso em relação à meta
        if (c.getValorMeta() != null && c.getValorMeta().compareTo(BigDecimal.ZERO) > 0) {
            BigDecimal falta = c.getValorMeta().subtract(valorAtual).max(BigDecimal.ZERO);
            dto.setFaltaParaMeta(falta);
            double pct = valorAtual.divide(c.getValorMeta(), 6, RoundingMode.HALF_UP)
                                   .multiply(BigDecimal.valueOf(100))
                                   .doubleValue();
            dto.setPercentualAtingido(Math.min(pct, 100.0));
        }

        // Taxa mensal efetiva
        double taxaMensal = calcularTaxaMensal(c);
        dto.setTaxaMensalEfetiva(taxaMensal);

        // Projeções com prazo
        if (c.getDataPrazo() != null && c.getDataPrazo().isAfter(LocalDate.now())) {
            int meses = (int) Period.between(LocalDate.now(), c.getDataPrazo()).toTotalMonths();
            dto.setMesesRestantes(meses);

            if (meses > 0) {
                double vp = valorAtual.doubleValue();
                double fatorN = Math.pow(1 + taxaMensal, meses);

                // Montante sem novos aportes: VP × (1+r)^n
                double montanteSemAportes = vp * fatorN;
                dto.setMontanteProjetadoSemAportes(
                        BigDecimal.valueOf(montanteSemAportes).setScale(2, RoundingMode.HALF_UP));

                // Aporte mensal sugerido (PMT)
                if (c.getValorMeta() != null) {
                    double vf = c.getValorMeta().doubleValue();
                    double pmt;
                    if (taxaMensal < 1e-10) {
                        // Taxa zero: divisão simples
                        pmt = Math.max(0, (vf - vp)) / meses;
                    } else {
                        pmt = Math.max(0, (vf - vp * fatorN) * taxaMensal / (fatorN - 1));
                    }
                    dto.setAporteMensalSugerido(
                            BigDecimal.valueOf(pmt).setScale(2, RoundingMode.HALF_UP));

                    // Montante com aportes: VP×(1+r)^n + PMT×[(1+r)^n − 1]/r
                    double montanteComAportes;
                    if (taxaMensal < 1e-10) {
                        montanteComAportes = vp + pmt * meses;
                    } else {
                        montanteComAportes = vp * fatorN + pmt * (fatorN - 1) / taxaMensal;
                    }
                    dto.setMontanteProjetadoComAportes(
                            BigDecimal.valueOf(montanteComAportes).setScale(2, RoundingMode.HALF_UP));

                    dto.setMetaAlcancavel(montanteComAportes >= vf - 0.01);
                }
            }
        }

        // Instituições com valor aportado por cada uma
        List<CaixinhaResponseDTO.InstituicaoDTO> instDtos = new ArrayList<>();
        List<CaixinhaInstituicao> vinculos = caixinhaInstituicaoRepository.findAllByCaixinha_Id(c.getId());
        for (CaixinhaInstituicao vi : vinculos) {
            List<EventoFinanceiro> eventosDaInst = eventoFinanceiroRepository
                    .findAllByCaixinha_Id(c.getId()).stream()
                    .filter(e -> e.getEventoInstituicoes() != null &&
                                 e.getEventoInstituicoes().stream()
                                   .anyMatch(ei -> ei.getInstituicaoUsuario().getId()
                                                     .equals(vi.getInstituicaoUsuario().getId())))
                    .toList();
            BigDecimal aportadoNaInst = eventosDaInst.stream()
                    .map(e -> BigDecimal.valueOf(e.getValor()))
                    .reduce(BigDecimal.ZERO, BigDecimal::add);

            CaixinhaResponseDTO.InstituicaoDTO iDto = new CaixinhaResponseDTO.InstituicaoDTO();
            iDto.setId(vi.getInstituicaoUsuario().getId());
            iDto.setNome(vi.getInstituicaoUsuario().getInstituicao().getNome());
            iDto.setValorAportado(aportadoNaInst);
            instDtos.add(iDto);
        }
        dto.setInstituicoes(instDtos);

        return dto;
    }

    /**
     * Calcula a taxa mensal efetiva a partir da configuração da caixinha.
     *
     * <ul>
     *   <li>CDI: taxaReferenciaAtual × (percentualRendimento / 100) / 12 (simplificado)</li>
     *   <li>SELIC: igual ao CDI</li>
     *   <li>POUPANÇA: 70% da SELIC + 0% TR simplificado</li>
     *   <li>PREFIXADO / PERSONALIZADO: taxa anual → mensal composto</li>
     * </ul>
     */
    private double calcularTaxaMensal(Caixinha c) {
        if (c.getTipoRendimento() == null || c.getTaxaReferenciaAtual() == null) {
            return 0.0;
        }

        double taxaAnualPercent;

        switch (c.getTipoRendimento()) {
            case CDI, SELIC -> {
                double referencia = c.getTaxaReferenciaAtual(); // % a.a.
                double percentual = c.getPercentualRendimento() != null
                        ? c.getPercentualRendimento() / 100.0 : 1.0;
                taxaAnualPercent = referencia * percentual;
            }
            case POUPANCA -> {
                // Regra atual da poupança: 70% da SELIC quando SELIC > 8,5% a.a.
                taxaAnualPercent = c.getTaxaReferenciaAtual() * 0.70;
            }
            case PREFIXADO, PERSONALIZADO -> {
                taxaAnualPercent = c.getTaxaAnualPersonalizada() != null
                        ? c.getTaxaAnualPersonalizada() : 0.0;
            }
            default -> taxaAnualPercent = 0.0;
        }

        // Converte % a.a. para decimal mensal via juros compostos: (1 + i_a)^(1/12) - 1
        return Math.pow(1 + taxaAnualPercent / 100.0, 1.0 / 12.0) - 1;
    }

    // =========================================================================
    // PRIVADO
    // =========================================================================

    // =========================================================================
    // PRIVADO
    // =========================================================================

    /**
     * Verifica se a caixinha atingiu o percentual de meta configurado pelo usuario
     * e envia o alerta de e-mail (uma vez por mes).
     */
    private void verificarEEnviarAlertaMeta(Caixinha caixinha, CaixinhaResponseDTO dto) {
        try {
            if (dto.getPercentualAtingido() == null || caixinha.getValorMeta() == null) return;

            configuracoesRepository.findConfiguracoesByUsuario_Id(caixinha.getUsuario().getId())
                    .ifPresent(config -> {
                        if (!config.getAlertasEmailAtivos().contains(TipoAlertaEmail.ALERTA_META_POUPANCA)) return;

                        int threshold = config.getPercentualAlertaMeta() != null
                                ? config.getPercentualAlertaMeta() : 90;

                        if (dto.getPercentualAtingido() < threshold) return;

                        // Ja enviou este mes?
                        LocalDate hoje = java.time.LocalDate.now();
                        if (config.getUltimoAlertaMetaEnviado() != null
                                && config.getUltimoAlertaMetaEnviado().getMonth() == hoje.getMonth()
                                && config.getUltimoAlertaMetaEnviado().getYear() == hoje.getYear()) {
                            return;
                        }

                        emailService.enviarAlertaMetaPoupanca(
                                caixinha.getUsuario(),
                                caixinha.getNome(),
                                dto.getValorAtual(),
                                caixinha.getValorMeta(),
                                dto.getPercentualAtingido());

                        config.setUltimoAlertaMetaEnviado(hoje);
                        configuracoesRepository.save(config);
                    });
        } catch (Exception e) {
            log.warn("[CaixinhaService] Erro ao verificar alerta de meta: {}", e.getMessage());
        }
    }

    private void validarUsuario(UUID usuarioId) {
        if (!usuarioRepository.existsById(usuarioId)) {
            throw new EntidadeNaoEncontradaException(
                    "Usuário de id: %s não encontrado.".formatted(usuarioId));
        }
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.configuracoes.in.ConfiguracaoEditDTO;
import controle.api.back_end.dto.configuracoes.in.PeriodoTempoRequestDto;
import controle.api.back_end.exception.EntidadeJaExisteException;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.model.categoria.CategoriaUsuario;
import controle.api.back_end.model.configuracoes.Configuracoes;
import controle.api.back_end.model.configuracoes.LimitePorCategoria;
import controle.api.back_end.model.configuracoes.LimitePorInstituicao;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.instituicao.InstituicaoUsuario;
import controle.api.back_end.model.usuario.Usuario;
import controle.api.back_end.repository.categoria.CategoriaUsuarioRepository;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import controle.api.back_end.repository.configuracoes.LimitePorCategoriaRepository;
import controle.api.back_end.repository.configuracoes.LimitePorInstituicaoRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoDetalheRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoInstituicaoRepository;
import controle.api.back_end.repository.instituicao.InstituicaoUsuarioRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import jakarta.transaction.Transactional;
import jakarta.validation.Valid;
import org.springframework.stereotype.Service;

import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;

@Service
public class ConfiguracoesService {

    private final ConfiguracoesRepository configuracoesRepository;
    private final UsuarioRepository usuarioRepository;
    private final CategoriaUsuarioRepository categoriaUsuarioRepository;
    private final LimitePorCategoriaRepository limitePorCategoriaRepository;
    private final InstituicaoUsuarioRepository instituicaoUsuarioRepository;
    private final LimitePorInstituicaoRepository limitePorInstiuicaoRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final EventoInstituicaoRepository eventoInstituicaoRepository;
    private final EventoDetalheRepository eventoDetalheRepository;

    public ConfiguracoesService(ConfiguracoesRepository configuracoesRepository,
                                UsuarioRepository usuarioRepository,
                                CategoriaUsuarioRepository categoriaUsuarioRepository,
                                LimitePorCategoriaRepository limitePorCategoriaRepository,
                                InstituicaoUsuarioRepository instituicaoUsuarioRepository,
                                LimitePorInstituicaoRepository limitePorInstiuicaoRepository,
                                EventoFinanceiroRepository eventoFinanceiroRepository,
                                EventoInstituicaoRepository eventoInstituicaoRepository,
                                EventoDetalheRepository eventoDetalheRepository) {
        this.configuracoesRepository = configuracoesRepository;
        this.usuarioRepository = usuarioRepository;
        this.categoriaUsuarioRepository = categoriaUsuarioRepository;
        this.limitePorCategoriaRepository = limitePorCategoriaRepository;
        this.instituicaoUsuarioRepository = instituicaoUsuarioRepository;
        this.limitePorInstiuicaoRepository = limitePorInstiuicaoRepository;
        this.eventoFinanceiroRepository = eventoFinanceiroRepository;
        this.eventoInstituicaoRepository = eventoInstituicaoRepository;
        this.eventoDetalheRepository = eventoDetalheRepository;
    }

    public Page<Configuracoes> getConfiguracoes(Pageable pageable) {
        return configuracoesRepository.findAll(pageable);
    }



    public Configuracoes createConfiguracao(Configuracoes entity, UUID idUsuario) {
        Usuario user = usuarioRepository.findById(idUsuario)
                .orElseThrow(() -> new EntidadeNaoEncontradaException("Usuário não encontrado"));

        if (configuracoesRepository.existsConfiguracoesByUsuario_Id(idUsuario)) {
            throw new EntidadeJaExisteException("Já existe uma configuração associada ao usuário informado");
        }

        entity.setUsuario(user);
        entity.setUltimaAtualizacao(LocalDate.now());

        return configuracoesRepository.save(entity);
    }


    public Configuracoes editConfiguracao(Configuracoes entity,
                                          @Valid ConfiguracaoEditDTO editDTO,
                                          UUID id) {

        Configuracoes configuracao = configuracoesRepository.findById(id)
                .orElseThrow(() ->
                                new EntidadeNaoEncontradaException(
                                        "Configuração de Id: %s não encontrada."
                                                .formatted(id)
                                )
                );

        entity.setId(configuracao.getId());
        entity.setUsuario(configuracao.getUsuario());

        entity.setUltimaAtualizacao(LocalDate.now());
        // Limites por categoria
        if (editDTO.getLimitesCategoria() != null) {
            List<LimitePorCategoria> limitesCategoria = new ArrayList<>();
            for (ConfiguracaoEditDTO.LimiteCategoriaEditDTO limiteDTO : editDTO.getLimitesCategoria()) {
                CategoriaUsuario categoriaUsuario = categoriaUsuarioRepository
                        .findByUsuario_idAndCategoria_id(configuracao.getUsuario().getId(), limiteDTO.getCategoriaId());

                LimitePorCategoria limite = limitePorCategoriaRepository
                        .findByConfiguracoesAndCategoriaUsuario(configuracao, categoriaUsuario);

                if (limite == null) {
                    limite = new LimitePorCategoria();
                    limite.setConfiguracoes(configuracao);
                    limite.setCategoriaUsuario(categoriaUsuario);
                }

                limite.setLimiteDesejado(limiteDTO.getValor());
                LimitePorCategoria save = limitePorCategoriaRepository.save(limite);
                limitesCategoria.add(save);
            }
            entity.setLimitePorCategoria(limitesCategoria);
        }

        // Limites por instituição
        if (editDTO.getLimitesInstituicao() != null) {
            List<LimitePorInstituicao> limitesInstituicao = new ArrayList<>();
            for (ConfiguracaoEditDTO.LimiteInstituicaoEditDTO limiteDTO : editDTO.getLimitesInstituicao()) {
                InstituicaoUsuario instituicaoUsuario = instituicaoUsuarioRepository
                        .findByUsuario_IdAndInstituicao_Id(configuracao.getUsuario().getId(), limiteDTO.getInstituicaoId());

                LimitePorInstituicao limite = limitePorInstiuicaoRepository
                        .findByConfiguracoesAndInstituicaoUsuario(configuracao, instituicaoUsuario);

                if (limite == null) {
                    limite = new LimitePorInstituicao();
                    limite.setConfiguracoes(configuracao);
                    limite.setInstituicaoUsuario(instituicaoUsuario);
                }

                limite.setLimiteDesejado(limiteDTO.getValor());
                LimitePorInstituicao save = limitePorInstiuicaoRepository.save(limite);
                limitesInstituicao.add(save);
            }
            entity.setLimitePorInstituicao(limitesInstituicao);
        }

        return configuracoesRepository.save(entity);
    }

    public LimitePorCategoria createLimitePorCategoria(CategoriaUsuario categoriaUsuario, Double valor){
        LimitePorCategoria limiteCategoria = new LimitePorCategoria();
        limiteCategoria.setCategoriaUsuario(categoriaUsuario);
        limiteCategoria.setLimiteDesejado(valor);
        return limitePorCategoriaRepository.save(limiteCategoria);
    }

    public List<LimitePorCategoria> createLimitePorCategoria(List<CategoriaUsuario> categorias, List<Double> valores){
       List<LimitePorCategoria> limites = new ArrayList<>();
        for (int c = 0;categorias.size()>c;c++){
            LimitePorCategoria limitePorCategoria = new LimitePorCategoria();
            limitePorCategoria.setCategoriaUsuario(categorias.get(c));
            limitePorCategoria.setLimiteDesejado(valores.get(c));

            limites.add(limitePorCategoria);
        }
        return limites;
    }

    public LimitePorInstituicao createLimitePorInstituicao(InstituicaoUsuario instituicaoUsuario, Double valor){

        LimitePorInstituicao limiteInstituicao = new LimitePorInstituicao();
        List<LimitePorInstituicao> limitePorInstituicaoByInstitucaoUsuarioId = limitePorInstiuicaoRepository
                .findLimitePorInstituicaoByInstituicaoUsuario_Id(
                        instituicaoUsuario.getId()
                );

        limiteInstituicao.setInstituicaoUsuario(instituicaoUsuario);
        limiteInstituicao.setLimiteDesejado(valor);
        return limitePorInstiuicaoRepository.save(limiteInstituicao);
    }

    public InstituicaoUsuario findInstituicaoUsuario(Integer institucaoUsuarioId) {
        return instituicaoUsuarioRepository.findById(institucaoUsuarioId)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Associação de instituição e usuário com o id: %d não encontrada."
                                        .formatted(institucaoUsuarioId)
                        )
                );
    }
    public CategoriaUsuario findCategoriaUsuario(Integer categoriaUsuarioId) {
        return categoriaUsuarioRepository.findById(categoriaUsuarioId)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Associação de categoria e usuário com o id: %d não encontrada."
                                        .formatted(categoriaUsuarioId)
                        )
                );
    }

    public Configuracoes updateLimiteInstituicao(UUID id, List<LimitePorInstituicao> limites) {
        Configuracoes configuracoes = configuracoesRepository.findById(id)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Configuração de id: %s não encontrado."
                                        .formatted(id)
                        )
                );
        configuracoes.setLimitePorInstituicao(limites);
        return configuracoesRepository.save(configuracoes);
    }


    public Configuracoes updateLimiteCategoria(UUID id, List<LimitePorCategoria> limites) {
        Configuracoes configuracoes = configuracoesRepository.findById(id)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Configuração de id: %s não encontrado."
                                        .formatted(id)
                        )
                );
        configuracoes.setLimitePorCategoria(limites);
        return configuracoesRepository.save(configuracoes);
    }

    @Transactional
    public void deleteByPeriodoDeTempo(UUID id,@Valid PeriodoTempoRequestDto tempoDto) {
       Configuracoes config = getConfiguracoesById(id);

        UUID idUsuario = config.getUsuario().getId();

        List<EventoFinanceiro> eventosFinanceiros = eventoFinanceiroRepository
                .findEventoFinanceiroByUsuario_Id(idUsuario)
                .stream()
                .filter(evento -> !evento.getDataEvento().isBefore(tempoDto.getDataInical())
                        && !evento.getDataEvento().isAfter(tempoDto.getDataFinal()))
                .toList();

        if (eventosFinanceiros.isEmpty()) {
            throw new EntidadeNaoEncontradaException("Nenhum evento encontrado no período informado.");
        }

        for (EventoFinanceiro evento : eventosFinanceiros) {
            if (evento.getGastoDetalhe() != null) {
                evento.getGastoDetalhe().getCategoriaUsuario().clear(); // limpa vínculos
                evento.setGastoDetalhe(null);
            }
            if (evento.getEventoInstituicoes() != null) {
                evento.getEventoInstituicoes().clear();
            }
        }
        eventoFinanceiroRepository.deleteAll(eventosFinanceiros);

    }

    @Transactional
    public void deleteAllByUsuario(UUID usuarioId) {
        Usuario usuario = usuarioRepository.findById(usuarioId)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Usuário de id: %s não encontrado.".formatted(usuarioId)
                        )
                );

        List<EventoFinanceiro> eventosFinanceiros = eventoFinanceiroRepository.findAllByUsuario(usuario);

        if (eventosFinanceiros.isEmpty()) {
            throw new EntidadeNaoEncontradaException("Nenhum evento encontrado para o usuário informado.");
        }

        eventoFinanceiroRepository.deleteAll(eventosFinanceiros);
    }

    public Configuracoes getConfiguracaoByUserId(UUID userId) {

       Configuracoes config = configuracoesRepository.findConfiguracoesByUsuario_Id(userId)
               .orElseThrow(()->
                       new EntidadeNaoEncontradaException("Não foi possível encontrar a configuração correspondente" +
                               " ao usuário de id: %s"
                               .formatted(userId)
                       )
               );
        List<LimitePorCategoria> limitePorCategoriaByConfiguracoesId = limitePorCategoriaRepository.findLimitePorCategoriaByConfiguracoes_Id(config.getId());
        List<LimitePorInstituicao> limitePorInstituicaoByConfiguracoesId = limitePorInstiuicaoRepository.findLimitePorInstituicaoByConfiguracoes_Id(config.getId());

        config.setLimitePorCategoria(limitePorCategoriaByConfiguracoesId);
        config.setLimitePorInstituicao(limitePorInstituicaoByConfiguracoesId);

        return config;
    }

    public Configuracoes getConfiguracoesById(UUID configId){
        Configuracoes config = configuracoesRepository.findById(configId)
                .orElseThrow(() ->
                    new EntidadeNaoEncontradaException(
                            "Configurações de id: %s não encontrada."
                                    .formatted(configId)
                    )
                );
        List<LimitePorCategoria> limitePorCategoriaByConfiguracoesId = limitePorCategoriaRepository.findLimitePorCategoriaByConfiguracoes_Id(config.getId());
        List<LimitePorInstituicao> limitePorInstituicaoByConfiguracoesId = limitePorInstiuicaoRepository.findLimitePorInstituicaoByConfiguracoes_Id(config.getId());

        config.setLimitePorCategoria(limitePorCategoriaByConfiguracoesId);
        config.setLimitePorInstituicao(limitePorInstituicaoByConfiguracoesId);
        return config;
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.configuracoes.in.ConfiguracaoEditDTO;
import controle.api.back_end.dto.configuracoes.in.PeriodoTempoRequestDto;
import controle.api.back_end.exception.EntidadeJaExisteException;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.model.categoria.CategoriaUsuario;
import controle.api.back_end.model.configuracoes.Configuracoes;
import controle.api.back_end.model.configuracoes.LimitePorCategoria;
import controle.api.back_end.model.configuracoes.LimitePorInstituicao;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.instituicao.InstituicaoUsuario;
import controle.api.back_end.model.usuario.Usuario;
import controle.api.back_end.repository.categoria.CategoriaUsuarioRepository;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import controle.api.back_end.repository.configuracoes.LimitePorCategoriaRepository;
import controle.api.back_end.repository.configuracoes.LimitePorInstituicaoRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoDetalheRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoInstituicaoRepository;
import controle.api.back_end.repository.instituicao.InstituicaoUsuarioRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import jakarta.transaction.Transactional;
import jakarta.validation.Valid;
import org.springframework.stereotype.Service;

import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;

@Service
public class ConfiguracoesService {

    private final ConfiguracoesRepository configuracoesRepository;
    private final UsuarioRepository usuarioRepository;
    private final CategoriaUsuarioRepository categoriaUsuarioRepository;
    private final LimitePorCategoriaRepository limitePorCategoriaRepository;
    private final InstituicaoUsuarioRepository instituicaoUsuarioRepository;
    private final LimitePorInstituicaoRepository limitePorInstiuicaoRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final EventoInstituicaoRepository eventoInstituicaoRepository;
    private final EventoDetalheRepository eventoDetalheRepository;

    public ConfiguracoesService(ConfiguracoesRepository configuracoesRepository,
                                UsuarioRepository usuarioRepository,
                                CategoriaUsuarioRepository categoriaUsuarioRepository,
                                LimitePorCategoriaRepository limitePorCategoriaRepository,
                                InstituicaoUsuarioRepository instituicaoUsuarioRepository,
                                LimitePorInstituicaoRepository limitePorInstiuicaoRepository,
                                EventoFinanceiroRepository eventoFinanceiroRepository,
                                EventoInstituicaoRepository eventoInstituicaoRepository,
                                EventoDetalheRepository eventoDetalheRepository) {
        this.configuracoesRepository = configuracoesRepository;
        this.usuarioRepository = usuarioRepository;
        this.categoriaUsuarioRepository = categoriaUsuarioRepository;
        this.limitePorCategoriaRepository = limitePorCategoriaRepository;
        this.instituicaoUsuarioRepository = instituicaoUsuarioRepository;
        this.limitePorInstiuicaoRepository = limitePorInstiuicaoRepository;
        this.eventoFinanceiroRepository = eventoFinanceiroRepository;
        this.eventoInstituicaoRepository = eventoInstituicaoRepository;
        this.eventoDetalheRepository = eventoDetalheRepository;
    }

    public Page<Configuracoes> getConfiguracoes(Pageable pageable) {
        return configuracoesRepository.findAll(pageable);
    }



    public Configuracoes createConfiguracao(Configuracoes entity, UUID idUsuario) {
        Usuario user = usuarioRepository.findById(idUsuario)
                .orElseThrow(() -> new EntidadeNaoEncontradaException("Usuário não encontrado"));

        if (configuracoesRepository.existsConfiguracoesByUsuario_Id(idUsuario)) {
            throw new EntidadeJaExisteException("Já existe uma configuração associada ao usuário informado");
        }

        entity.setUsuario(user);
        entity.setUltimaAtualizacao(LocalDate.now());

        return configuracoesRepository.save(entity);
    }


    public Configuracoes editConfiguracao(Configuracoes entity,
                                          @Valid ConfiguracaoEditDTO editDTO,
                                          UUID id) {

        Configuracoes configuracao = configuracoesRepository.findById(id)
                .orElseThrow(() ->
                                new EntidadeNaoEncontradaException(
                                        "Configuração de Id: %s não encontrada."
                                                .formatted(id)
                                )
                );

        entity.setId(configuracao.getId());
        entity.setUsuario(configuracao.getUsuario());
        entity.setUltimaAtualizacao(LocalDate.now());

        // Preserva campos de e-mail existentes se nao forem sobrescritos
        entity.setAlertasEmailAtivos(
                editDTO.getAlertasEmailAtivos() != null
                        ? editDTO.getAlertasEmailAtivos()
                        : configuracao.getAlertasEmailAtivos());
        entity.setPercentualAlertaGasto(
                editDTO.getPercentualAlertaGasto() != null
                        ? editDTO.getPercentualAlertaGasto()
                        : configuracao.getPercentualAlertaGasto());
        entity.setPercentualAlertaMeta(
                editDTO.getPercentualAlertaMeta() != null
                        ? editDTO.getPercentualAlertaMeta()
                        : configuracao.getPercentualAlertaMeta());

        // Preserva datas de controle de envio
        entity.setUltimoAlertaGastoEnviado(configuracao.getUltimoAlertaGastoEnviado());
        entity.setUltimoAlertaMetaEnviado(configuracao.getUltimoAlertaMetaEnviado());
        // Limites por categoria
        if (editDTO.getLimitesCategoria() != null) {
            List<LimitePorCategoria> limitesCategoria = new ArrayList<>();
            for (ConfiguracaoEditDTO.LimiteCategoriaEditDTO limiteDTO : editDTO.getLimitesCategoria()) {
                CategoriaUsuario categoriaUsuario = categoriaUsuarioRepository
                        .findByUsuario_idAndCategoria_id(configuracao.getUsuario().getId(), limiteDTO.getCategoriaId());

                LimitePorCategoria limite = limitePorCategoriaRepository
                        .findByConfiguracoesAndCategoriaUsuario(configuracao, categoriaUsuario);

                if (limite == null) {
                    limite = new LimitePorCategoria();
                    limite.setConfiguracoes(configuracao);
                    limite.setCategoriaUsuario(categoriaUsuario);
                }

                limite.setLimiteDesejado(limiteDTO.getValor());
                LimitePorCategoria save = limitePorCategoriaRepository.save(limite);
                limitesCategoria.add(save);
            }
            entity.setLimitePorCategoria(limitesCategoria);
        }

        // Limites por instituição
        if (editDTO.getLimitesInstituicao() != null) {
            List<LimitePorInstituicao> limitesInstituicao = new ArrayList<>();
            for (ConfiguracaoEditDTO.LimiteInstituicaoEditDTO limiteDTO : editDTO.getLimitesInstituicao()) {
                InstituicaoUsuario instituicaoUsuario = instituicaoUsuarioRepository
                        .findByUsuario_IdAndInstituicao_Id(configuracao.getUsuario().getId(), limiteDTO.getInstituicaoId());

                LimitePorInstituicao limite = limitePorInstiuicaoRepository
                        .findByConfiguracoesAndInstituicaoUsuario(configuracao, instituicaoUsuario);

                if (limite == null) {
                    limite = new LimitePorInstituicao();
                    limite.setConfiguracoes(configuracao);
                    limite.setInstituicaoUsuario(instituicaoUsuario);
                }

                limite.setLimiteDesejado(limiteDTO.getValor());
                LimitePorInstituicao save = limitePorInstiuicaoRepository.save(limite);
                limitesInstituicao.add(save);
            }
            entity.setLimitePorInstituicao(limitesInstituicao);
        }

        return configuracoesRepository.save(entity);
    }

    public LimitePorCategoria createLimitePorCategoria(CategoriaUsuario categoriaUsuario, Double valor){
        LimitePorCategoria limiteCategoria = new LimitePorCategoria();
        limiteCategoria.setCategoriaUsuario(categoriaUsuario);
        limiteCategoria.setLimiteDesejado(valor);
        return limitePorCategoriaRepository.save(limiteCategoria);
    }

    public List<LimitePorCategoria> createLimitePorCategoria(List<CategoriaUsuario> categorias, List<Double> valores){
       List<LimitePorCategoria> limites = new ArrayList<>();
        for (int c = 0;categorias.size()>c;c++){
            LimitePorCategoria limitePorCategoria = new LimitePorCategoria();
            limitePorCategoria.setCategoriaUsuario(categorias.get(c));
            limitePorCategoria.setLimiteDesejado(valores.get(c));

            limites.add(limitePorCategoria);
        }
        return limites;
    }

    public LimitePorInstituicao createLimitePorInstituicao(InstituicaoUsuario instituicaoUsuario, Double valor){

        LimitePorInstituicao limiteInstituicao = new LimitePorInstituicao();
        List<LimitePorInstituicao> limitePorInstituicaoByInstitucaoUsuarioId = limitePorInstiuicaoRepository
                .findLimitePorInstituicaoByInstituicaoUsuario_Id(
                        instituicaoUsuario.getId()
                );

        limiteInstituicao.setInstituicaoUsuario(instituicaoUsuario);
        limiteInstituicao.setLimiteDesejado(valor);
        return limitePorInstiuicaoRepository.save(limiteInstituicao);
    }

    public InstituicaoUsuario findInstituicaoUsuario(Integer institucaoUsuarioId) {
        return instituicaoUsuarioRepository.findById(institucaoUsuarioId)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Associação de instituição e usuário com o id: %d não encontrada."
                                        .formatted(institucaoUsuarioId)
                        )
                );
    }
    public CategoriaUsuario findCategoriaUsuario(Integer categoriaUsuarioId) {
        return categoriaUsuarioRepository.findById(categoriaUsuarioId)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Associação de categoria e usuário com o id: %d não encontrada."
                                        .formatted(categoriaUsuarioId)
                        )
                );
    }

    public Configuracoes updateLimiteInstituicao(UUID id, List<LimitePorInstituicao> limites) {
        Configuracoes configuracoes = configuracoesRepository.findById(id)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Configuração de id: %s não encontrado."
                                        .formatted(id)
                        )
                );
        configuracoes.setLimitePorInstituicao(limites);
        return configuracoesRepository.save(configuracoes);
    }


    public Configuracoes updateLimiteCategoria(UUID id, List<LimitePorCategoria> limites) {
        Configuracoes configuracoes = configuracoesRepository.findById(id)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Configuração de id: %s não encontrado."
                                        .formatted(id)
                        )
                );
        configuracoes.setLimitePorCategoria(limites);
        return configuracoesRepository.save(configuracoes);
    }

    @Transactional
    public void deleteByPeriodoDeTempo(UUID id,@Valid PeriodoTempoRequestDto tempoDto) {
       Configuracoes config = getConfiguracoesById(id);

        UUID idUsuario = config.getUsuario().getId();

        List<EventoFinanceiro> eventosFinanceiros = eventoFinanceiroRepository
                .findEventoFinanceiroByUsuario_Id(idUsuario)
                .stream()
                .filter(evento -> !evento.getDataEvento().isBefore(tempoDto.getDataInical())
                        && !evento.getDataEvento().isAfter(tempoDto.getDataFinal()))
                .toList();

        if (eventosFinanceiros.isEmpty()) {
            throw new EntidadeNaoEncontradaException("Nenhum evento encontrado no período informado.");
        }

        for (EventoFinanceiro evento : eventosFinanceiros) {
            if (evento.getGastoDetalhe() != null) {
                evento.getGastoDetalhe().getCategoriaUsuario().clear(); // limpa vínculos
                evento.setGastoDetalhe(null);
            }
            if (evento.getEventoInstituicoes() != null) {
                evento.getEventoInstituicoes().clear();
            }
        }
        eventoFinanceiroRepository.deleteAll(eventosFinanceiros);

    }

    @Transactional
    public void deleteAllByUsuario(UUID usuarioId) {
        Usuario usuario = usuarioRepository.findById(usuarioId)
                .orElseThrow(() ->
                        new EntidadeNaoEncontradaException(
                                "Usuário de id: %s não encontrado.".formatted(usuarioId)
                        )
                );

        List<EventoFinanceiro> eventosFinanceiros = eventoFinanceiroRepository.findAllByUsuario(usuario);

        if (eventosFinanceiros.isEmpty()) {
            throw new EntidadeNaoEncontradaException("Nenhum evento encontrado para o usuário informado.");
        }

        eventoFinanceiroRepository.deleteAll(eventosFinanceiros);
    }

    public Configuracoes getConfiguracaoByUserId(UUID userId) {

       Configuracoes config = configuracoesRepository.findConfiguracoesByUsuario_Id(userId)
               .orElseThrow(()->
                       new EntidadeNaoEncontradaException("Não foi possível encontrar a configuração correspondente" +
                               " ao usuário de id: %s"
                               .formatted(userId)
                       )
               );
        List<LimitePorCategoria> limitePorCategoriaByConfiguracoesId = limitePorCategoriaRepository.findLimitePorCategoriaByConfiguracoes_Id(config.getId());
        List<LimitePorInstituicao> limitePorInstituicaoByConfiguracoesId = limitePorInstiuicaoRepository.findLimitePorInstituicaoByConfiguracoes_Id(config.getId());

        config.setLimitePorCategoria(limitePorCategoriaByConfiguracoesId);
        config.setLimitePorInstituicao(limitePorInstituicaoByConfiguracoesId);

        return config;
    }

    public Configuracoes getConfiguracoesById(UUID configId){
        Configuracoes config = configuracoesRepository.findById(configId)
                .orElseThrow(() ->
                    new EntidadeNaoEncontradaException(
                            "Configurações de id: %s não encontrada."
                                    .formatted(configId)
                    )
                );
        List<LimitePorCategoria> limitePorCategoriaByConfiguracoesId = limitePorCategoriaRepository.findLimitePorCategoriaByConfiguracoes_Id(config.getId());
        List<LimitePorInstituicao> limitePorInstituicaoByConfiguracoesId = limitePorInstiuicaoRepository.findLimitePorInstituicaoByConfiguracoes_Id(config.getId());

        config.setLimitePorCategoria(limitePorCategoriaByConfiguracoesId);
        config.setLimitePorInstituicao(limitePorInstituicaoByConfiguracoesId);
        return config;
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.model.usuario.Usuario;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.mail.SimpleMailMessage;
import org.springframework.mail.javamail.JavaMailSender;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Servico responsavel pelo envio de e-mails de alertas, relatorios e
 * mensagens especiais (aniversario) para os usuarios.
 *
 * <h3>Para ativar o envio real de e-mails</h3>
 * <ol>
 *   <li>Configure as propriedades {@code spring.mail.*} no {@code application.properties}.</li>
 *   <li>Mude {@code app.email.habilitado=true}.</li>
 *   <li>No Gmail: gere uma "Senha de app" em Minha Conta {@literal >} Seguranca {@literal >} Senhas de app.</li>
 * </ol>
 *
 * <p>Enquanto desabilitado ({@code app.email.habilitado=false}), todos os envios sao
 * apenas logados — nenhum e-mail e enviado de fato.
 */
@Service
public class EmailService {

    private static final Logger log = LoggerFactory.getLogger(EmailService.class);
    private static final DateTimeFormatter FMT_BR = DateTimeFormatter.ofPattern("dd/MM/yyyy");
    private static final String SEP = "================================================";

    /** Injecao opcional: se spring-boot-starter-mail nao estiver configurado, sera null. */
    @Autowired(required = false)
    private JavaMailSender mailSender;

    @Value("${app.email.habilitado:false}")
    private boolean habilitado;

    @Value("${app.email.remetente:noreply@myfinance.app}")
    private String remetente;

    // =========================================================================
    // ALERTA: LIMITE MENSAL DE GASTOS
    // =========================================================================

    /**
     * Enviado quando o usuario atinge {@code percentualAtingido}% do limite mensal.
     *
     * @param usuario          destinatario
     * @param gastoAtual       total gasto no mes ate agora
     * @param limiteMensal     limite configurado pelo usuario
     * @param percentualConfig percentual que disparou o alerta (ex.: 80)
     * @param percentualReal   percentual real atual (pode ser maior que percentualConfig)
     */
    public void enviarAlertaLimiteMensal(Usuario usuario,
                                         double gastoAtual,
                                         double limiteMensal,
                                         int percentualConfig,
                                         double percentualReal) {
        String assunto = String.format("[MyFinance] Alerta: %d%% do limite mensal atingido", percentualConfig);

        StringBuilder sb = new StringBuilder();
        sb.append("Ola, ").append(usuario.getNome()).append("!\n\n");
        sb.append(SEP).append("\n");
        sb.append("  ALERTA DE LIMITE MENSAL\n");
        sb.append(SEP).append("\n\n");

        sb.append("Voce ja usou ").append(String.format("%.1f%%", percentualReal))
          .append(" do seu limite de gastos mensais.\n\n");

        sb.append("  Gasto atual:     R$ ").append(String.format("%.2f", gastoAtual)).append("\n");
        sb.append("  Limite mensal:   R$ ").append(String.format("%.2f", limiteMensal)).append("\n");
        sb.append("  Restante:        R$ ").append(String.format("%.2f", limiteMensal - gastoAtual)).append("\n\n");

        if (percentualReal >= 100) {
            sb.append("Atencao: voce ultrapassou o limite que definiu para este mes.\n");
            sb.append("Considere revisar seus gastos ou ajustar o limite nas configuracoes.\n\n");
        } else {
            sb.append("Fique de olho nos seus gastos para nao ultrapassar o limite!\n\n");
        }

        sb.append("Acesse o app para ver o detalhamento completo.\n\n");
        sb.append("-- Equipe MyFinance");

        enviar(usuario.getEmail(), assunto, sb.toString());
    }

    // =========================================================================
    // ALERTA: META DE POUPANCA
    // =========================================================================

    /**
     * Enviado quando uma caixinha atinge o percentual configurado da meta.
     *
     * @param usuario        destinatario
     * @param nomeCaixinha   nome da caixinha (ex.: "Viagem para o Japao")
     * @param valorAtual     saldo atual da caixinha
     * @param meta           valor da meta
     * @param percentualReal percentual real atingido
     */
    public void enviarAlertaMetaPoupanca(Usuario usuario,
                                          String nomeCaixinha,
                                          BigDecimal valorAtual,
                                          BigDecimal meta,
                                          double percentualReal) {
        String emoji = percentualReal >= 100 ? "PARABENS" : "QUASE LA";
        String assunto = String.format("[MyFinance] %s! Meta '%s' %.0f%% concluida",
                emoji, nomeCaixinha, percentualReal);

        StringBuilder sb = new StringBuilder();
        sb.append("Ola, ").append(usuario.getNome()).append("!\n\n");
        sb.append(SEP).append("\n");
        sb.append("  ALERTA DE META DE POUPANCA\n");
        sb.append(SEP).append("\n\n");

        if (percentualReal >= 100) {
            sb.append("Incrivel! Voce atingiu 100% da sua meta \"").append(nomeCaixinha).append("\"!\n\n");
            sb.append("Esse e o resultado de disciplina e foco. Parabens!\n\n");
        } else {
            sb.append("Voce esta chegando la! A caixinha \"").append(nomeCaixinha)
              .append("\" atingiu ").append(String.format("%.1f%%", percentualReal)).append(" da meta.\n\n");
        }

        sb.append("  Caixinha:     ").append(nomeCaixinha).append("\n");
        sb.append("  Saldo atual:  R$ ").append(valorAtual).append("\n");
        sb.append("  Meta:         R$ ").append(meta).append("\n");
        sb.append("  Progresso:    ").append(String.format("%.1f%%", percentualReal)).append("\n");

        if (percentualReal < 100 && meta != null) {
            BigDecimal falta = meta.subtract(valorAtual).max(BigDecimal.ZERO);
            sb.append("  Falta:        R$ ").append(falta).append("\n");
        }
        sb.append("\n");

        sb.append("Continue assim, voce esta quase la!\n\n");
        sb.append("-- Equipe MyFinance");

        enviar(usuario.getEmail(), assunto, sb.toString());
    }

    // =========================================================================
    // FELIZ ANIVERSARIO
    // =========================================================================

    /** Enviado no dia do aniversario do usuario. */
    public void enviarFelizAniversario(Usuario usuario) {
        String assunto = "[MyFinance] Feliz aniversario, " + usuario.getNome() + "!";

        StringBuilder sb = new StringBuilder();
        sb.append("Feliz aniversario, ").append(usuario.getNome()).append("!\n\n");
        sb.append(SEP).append("\n");
        sb.append("  PARABENS PELO SEU DIA!\n");
        sb.append(SEP).append("\n\n");

        sb.append("Hoje e um dia especial e queremos te desejar tudo de bom!\n\n");
        sb.append("Que este novo ano de vida seja cheio de realizacoes,\n");
        sb.append("saude, felicidade... e muito planejamento financeiro!\n\n");
        sb.append("Aproveite o dia. Voce merece!\n\n");
        sb.append("Com carinho,\n");
        sb.append("-- Equipe MyFinance");

        enviar(usuario.getEmail(), assunto, sb.toString());
    }

    // =========================================================================
    // RELATORIO MENSAL
    // =========================================================================

    /**
     * Relatorio completo enviado no dia 1 de cada mes com resumo de gastos e poupancas.
     *
     * @param usuario        destinatario
     * @param caixinhas      lista de caixinhas ativas com calculos
     * @param gastoMes       total gasto no mes anterior
     * @param limiteMensal   limite configurado (0 = nao configurado)
     */
    public void enviarRelatorioMensal(Usuario usuario,
                                       List<CaixinhaResponseDTO> caixinhas,
                                       double gastoMes,
                                       double limiteMensal) {
        String mesRef = LocalDate.now().minusMonths(1)
                .format(DateTimeFormatter.ofPattern("MM/yyyy"));
        String assunto = "[MyFinance] Seu relatorio financeiro de " + mesRef;

        StringBuilder sb = new StringBuilder();
        sb.append("Ola, ").append(usuario.getNome()).append("!\n\n");
        sb.append(SEP).append("\n");
        sb.append("  RELATORIO MENSAL - ").append(mesRef).append("\n");
        sb.append(SEP).append("\n\n");

        // Resumo de gastos
        sb.append("GASTOS DO MES\n");
        sb.append("--------------\n");
        sb.append("  Total gasto:  R$ ").append(String.format("%.2f", gastoMes)).append("\n");
        if (limiteMensal > 0) {
            double pct = (gastoMes / limiteMensal) * 100;
            sb.append("  Limite:       R$ ").append(String.format("%.2f", limiteMensal)).append("\n");
            sb.append("  Utilizacao:   ").append(String.format("%.1f%%", pct)).append("\n");
        }
        sb.append("\n");

        // Resumo de poupancas
        if (!caixinhas.isEmpty()) {
            sb.append("CAIXINHAS DE POUPANCA\n");
            sb.append("----------------------\n");
            BigDecimal totalPoupado = BigDecimal.ZERO;
            for (CaixinhaResponseDTO c : caixinhas) {
                sb.append("  ").append(c.getNome()).append("\n");
                sb.append("    Saldo:    R$ ").append(c.getValorAtual()).append("\n");
                if (c.getValorMeta() != null) {
                    sb.append("    Meta:     R$ ").append(c.getValorMeta())
                      .append(" (").append(String.format("%.1f%%", c.getPercentualAtingido())).append(")\n");
                }
                if (c.getAporteMensalSugerido() != null) {
                    sb.append("    Aporte/mes sugerido: R$ ").append(c.getAporteMensalSugerido()).append("\n");
                }
                sb.append("\n");
                totalPoupado = totalPoupado.add(c.getValorAtual());
            }
            sb.append("  Total poupado: R$ ").append(totalPoupado).append("\n\n");
        }

        sb.append(SEP).append("\n");
        sb.append("Acesse o app para ver o detalhamento completo.\n\n");
        sb.append("-- Equipe MyFinance");

        enviar(usuario.getEmail(), assunto, sb.toString());
    }

    // =========================================================================
    // LEMBRETE DE APORTE (SEMANAL)
    // =========================================================================

    /** Lembrete semanal para realizar aportes nas caixinhas com meta pendente. */
    public void enviarLembreteAporte(Usuario usuario, List<CaixinhaResponseDTO> caixinhas) {
        String assunto = "[MyFinance] Lembrete: seus aportes da semana";

        StringBuilder sb = new StringBuilder();
        sb.append("Ola, ").append(usuario.getNome()).append("!\n\n");
        sb.append("Aqui esta o lembrete semanal das suas caixinhas de poupanca:\n\n");
        sb.append(SEP).append("\n");

        boolean temAporte = false;
        for (CaixinhaResponseDTO c : caixinhas) {
            if (c.getAporteMensalSugerido() != null
                    && c.getAporteMensalSugerido().compareTo(BigDecimal.ZERO) > 0) {
                sb.append("  ").append(c.getNome()).append("\n");
                sb.append("    Saldo atual: R$ ").append(c.getValorAtual()).append("\n");
                sb.append("    Progresso:   ").append(String.format("%.1f%%", c.getPercentualAtingido()))
                  .append(" da meta\n");
                sb.append("    Aporte/mes:  R$ ").append(c.getAporteMensalSugerido()).append("\n\n");
                temAporte = true;
            }
        }

        if (!temAporte) {
            sb.append("  Todas as suas metas estao em dia!\n\n");
        }

        sb.append(SEP).append("\n");
        sb.append("Acesse o app para registrar seus aportes. Cada real conta!\n\n");
        sb.append("-- Equipe MyFinance");

        enviar(usuario.getEmail(), assunto, sb.toString());
    }

    // =========================================================================
    // ENVIO CENTRAL
    // =========================================================================

    private void enviar(String destinatario, String assunto, String corpo) {
        if (!habilitado) {
            log.info("[EmailService] E-mail desabilitado. Para: '{}' | Assunto: '{}'",
                    destinatario, assunto);
            return;
        }

        if (mailSender == null) {
            log.error("[EmailService] JavaMailSender nao esta configurado. " +
                      "Configure spring.mail.* no application.properties.");
            return;
        }

        try {
            SimpleMailMessage msg = new SimpleMailMessage();
            msg.setFrom(remetente);
            msg.setTo(destinatario);
            msg.setSubject(assunto);
            msg.setText(corpo);
            mailSender.send(msg);
            log.info("[EmailService] E-mail enviado com sucesso para: {}", destinatario);
        } catch (Exception e) {
            log.error("[EmailService] Falha ao enviar para {}: {}", destinatario, e.getMessage());
        }
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.registros.mapper.RegistrosMapper;
import controle.api.back_end.dto.registros.out.RegistroResponseDto;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.exception.InstituicaoInativaException;
import controle.api.back_end.exception.SaldoInsuficienteException;
import controle.api.back_end.factory.EventoFinanceiroFactory;
import controle.api.back_end.factory.MovimentoFactory;
import controle.api.back_end.factory.RecorrenciaFactory;
import controle.api.back_end.model.categoria.CategoriaUsuario;
import controle.api.back_end.model.eventoFinanceiro.*;
import controle.api.back_end.model.eventoFinanceiro.recorrenciaFinanceira.RecorrenciaFinanceira;
import controle.api.back_end.model.instituicao.InstituicaoUsuario;
import controle.api.back_end.model.usuario.Usuario;
import controle.api.back_end.repository.categoria.CategoriaUsuarioRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoDetalheRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoInstituicaoRepository;
import controle.api.back_end.repository.instituicao.InstituicaoUsuarioRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import controle.api.back_end.specifications.EventoFinanceiroSpecifications;
import controle.api.back_end.strategy.eventoFinanceiro.EventoFinanceiroStrategy;
import controle.api.back_end.strategy.eventoFinanceiro.Registro;
import controle.api.back_end.strategy.movimento.MovimentoResultado;
import controle.api.back_end.strategy.movimento.MovimentoStrategy;
import controle.api.back_end.strategy.recorrenciaFinanceira.RecorrenciaStrategy;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.jpa.domain.Specification;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;
import java.util.stream.IntStream;
import java.util.Locale;

/**
 * Serviço principal de registros financeiros.
 *
 * <p>Responsabilidades:
 * <ul>
 *   <li>Consultar registros do usuário (com ou sem filtros)</li>
 *   <li>Criar eventos únicos, em lote ou recorrentes</li>
 *   <li>Editar eventos já existentes</li>
 *   <li>Excluir eventos</li>
 * </ul>
 *
 * <p>Exportação de arquivos (JSON, SQL, Excel, PDF) é responsabilidade de
 * {@link RegistroExportacaoService}.
 */
@Service
@Transactional
public class RegistroService {

    // Ordem de exibição dos tipos: Recebimento → Gasto → Transferencia → Poupanca → Emprestimo
    private static final Map<Tipo, Integer> TIPO_ORDEM = Map.of(
            Tipo.Recebimento, 0,
            Tipo.Gasto, 1,
            Tipo.Transferencia, 2,
            Tipo.Poupanca, 3,
            Tipo.Emprestimo, 4
    );
    private static final int REGISTROS_POR_PAGINA_PADRAO = 20;
    private static final int REGISTROS_POR_PAGINA_MINIMO  = 5;
    private static final int REGISTROS_POR_PAGINA_MAXIMO  = 100;

    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final EventoInstituicaoRepository eventoInstituicaoRepository;
    private final EventoDetalheRepository eventoDetalheRepository;
    private final CategoriaUsuarioRepository categoriaUsuarioRepository;
    private final UsuarioRepository usuarioRepository;
    private final InstituicaoUsuarioRepository instituicaoUsuarioRepository;
    private final MovimentoFactory movimentoFactory;
    private final EventoFinanceiroFactory eventoFinanceiroFactory;
    private final RecorrenciaFactory recorrenciaFactory;
    private final InstituicaoService instituicaoService;

    public RegistroService(EventoFinanceiroRepository eventoFinanceiroRepository,
                           EventoInstituicaoRepository eventoInstituicaoRepository,
                           EventoDetalheRepository eventoDetalheRepository,
                           CategoriaUsuarioRepository categoriaUsuarioRepository,
                           UsuarioRepository usuarioRepository,
                           InstituicaoUsuarioRepository instituicaoUsuarioRepository,
                           MovimentoFactory movimentoFactory,
                           EventoFinanceiroFactory eventoFinanceiroFactory,
                           RecorrenciaFactory recorrenciaFactory,
                           InstituicaoService instituicaoService) {
        this.eventoFinanceiroRepository  = eventoFinanceiroRepository;
        this.eventoInstituicaoRepository = eventoInstituicaoRepository;
        this.eventoDetalheRepository     = eventoDetalheRepository;
        this.categoriaUsuarioRepository  = categoriaUsuarioRepository;
        this.usuarioRepository           = usuarioRepository;
        this.instituicaoUsuarioRepository = instituicaoUsuarioRepository;
        this.movimentoFactory            = movimentoFactory;
        this.eventoFinanceiroFactory     = eventoFinanceiroFactory;
        this.recorrenciaFactory          = recorrenciaFactory;
        this.instituicaoService          = instituicaoService;
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    /**
     * Retorna todos os eventos financeiros do usuário, ordenados por data.
     */
    @Transactional(readOnly = true)
    public List<EventoFinanceiro> getEventosFinanceirosByUser(UUID userId) {
        if (!usuarioRepository.existsById(userId)) {
            throw new EntidadeNaoEncontradaException("Usuário de id: %s não encontrado.".formatted(userId));
        }
        return eventoFinanceiroRepository.getEventoFinanceirosByUsuario_id(userId);
    }

    /**
     * Para cada evento da lista, retorna suas instituições vinculadas (mesma ordem).
     */
    @Transactional(readOnly = true)
    public List<List<EventoInstituicao>> getEventosInstituicoesByEventoFinanceiro(List<EventoFinanceiro> eventos) {
        return eventos.stream()
                .map(ev -> eventoInstituicaoRepository.findEventoInstituicaoByEventoFinanceiro_Id(ev.getId()))
                .toList();
    }

    /**
     * Para cada evento da lista, retorna seu detalhe (título + categorias) (mesma ordem).
     */
    @Transactional(readOnly = true)
    public List<EventoDetalhe> getGastosDetalhesByEventoFinanceiro(List<EventoFinanceiro> eventos) {
        return eventos.stream()
                .map(ev -> {
                    if (!eventoFinanceiroRepository.existsById(ev.getId())) {
                        throw new EntidadeNaoEncontradaException(
                                "Evento financeiro de id: %s não encontrado.".formatted(ev.getId()));
                    }
                    return eventoDetalheRepository.findGastoDetalheByEventoFinanceiro(ev);
                })
                .toList();
    }

    /**
     * Retorna o saldo acumulado na poupança do usuário.
     */
    @Transactional(readOnly = true)
    public Double getSaldoPoupanca(UUID userId) {
        buscarUsuarioOuErro(userId); // valida existência
        // TODO: implementar cálculo real com base nos eventos de poupança
        return 0.0;
    }

    /**
     * Retorna os anos distintos em que o usuário possui registros (mais recente primeiro).
     */
    @Transactional(readOnly = true)
    public List<Integer> getAnosByUserId(UUID userId) {
        buscarUsuarioOuErro(userId);
        return eventoFinanceiroRepository.findDistinctAnosByUserId(userId);
    }

    /**
     * Retorna os meses distintos em que o usuário possui registros no ano informado (1–12).
     */
    @Transactional(readOnly = true)
    public List<Integer> getMesesByUserIdAndAno(UUID userId, int ano) {
        buscarUsuarioOuErro(userId);
        return eventoFinanceiroRepository.findDistinctMesesByUserIdAndAno(userId, ano);
    }

    /**
     * Retorna os registros do mês/ano de forma paginada,
     * ordenados por: dia ASC → tipo (Recebimento primeiro) → título ASC.
     *
     * @param tamanho itens por página; limitado entre {@value #REGISTROS_POR_PAGINA_MINIMO}
     *                e {@value #REGISTROS_POR_PAGINA_MAXIMO}. Padrão: {@value #REGISTROS_POR_PAGINA_PADRAO}.
     */
    @Transactional(readOnly = true)
    public Page<RegistroResponseDto> getRegistrosByMes(UUID userId, int ano, int mes, int pagina, int tamanho) {
        buscarUsuarioOuErro(userId);

        // Garante que o tamanho esteja dentro dos limites permitidos
        int tamanhoPagina = Math.max(REGISTROS_POR_PAGINA_MINIMO,
                            Math.min(tamanho, REGISTROS_POR_PAGINA_MAXIMO));

        // Busca todos os eventos do mês com EventoDetalhe pré-carregado via JOIN FETCH
        List<EventoFinanceiro> todos =
                eventoFinanceiroRepository.findByUserIdAndAnoAndMes(userId, ano, mes);

        // Ordena: dia → tipo customizado → título alfabético
        List<EventoFinanceiro> ordenados = todos.stream()
                .sorted(Comparator
                        .comparing(EventoFinanceiro::getDataEvento)
                        .thenComparingInt(e -> TIPO_ORDEM.getOrDefault(e.getTipo(), 99))
                        .thenComparing(e -> {
                            EventoDetalhe d = e.getGastoDetalhe();
                            return (d != null && d.getTituloGasto() != null)
                                    ? d.getTituloGasto().toLowerCase(Locale.ROOT) : "";
                        }))
                .toList();

        int total = ordenados.size();
        int start = pagina * tamanhoPagina;

        if (start >= total) {
            return new PageImpl<>(List.of(), PageRequest.of(pagina, tamanhoPagina), total);
        }

        int end = Math.min(start + tamanhoPagina, total);

        // Mapeia apenas os itens da página atual — instituicoes são lazy mas a sessão está aberta
        List<RegistroResponseDto> dtos = ordenados.subList(start, end).stream()
                .map(ev -> RegistrosMapper.toResponse(ev, ev.getEventoInstituicoes(), ev.getGastoDetalhe()))
                .filter(Objects::nonNull)
                .toList();

        return new PageImpl<>(dtos, PageRequest.of(pagina, tamanhoPagina), total);
    }

    /**
     * Busca registros aplicando filtros dinâmicos. Todos os parâmetros são opcionais.
     */
    @Transactional(readOnly = true)
    public List<RegistroResponseDto> getByFilter(UUID userId,
                                                  Double valor,
                                                  List<TipoMovimento> tiposMovimento,
                                                  List<Tipo> tipos,
                                                  LocalDate dataEvento,
                                                  List<InstituicaoUsuario> instituicoes,
                                                  List<CategoriaUsuario> categorias,
                                                  String descricao,
                                                  String titulo) {
        Usuario usuario = buscarUsuarioOuErro(userId);

        Specification<EventoFinanceiro> filtroUsuario =
                (root, query, cb) -> cb.equal(root.get("usuario"), usuario);

        Specification<EventoFinanceiro> filtros = EventoFinanceiroSpecifications.porFiltros(
                valor, tipos, dataEvento, descricao, tiposMovimento, instituicoes, categorias, titulo);

        return eventoFinanceiroRepository.findAll(filtroUsuario.and(filtros)).stream()
                .map(ev -> RegistrosMapper.toResponse(ev, ev.getEventoInstituicoes(), ev.getGastoDetalhe()))
                .collect(Collectors.toList());
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    /**
     * Cria um registro financeiro completo (evento + meios de pagamento + detalhe).
     *
     * <p>As regras de cada tipo são aplicadas via Strategy:
     * <ul>
     *   <li><b>Gasto</b> → debita da(s) instituição(ões); valida saldo.</li>
     *   <li><b>Recebimento</b> → credita na(s) instituição(ões).</li>
     *   <li><b>Transferência</b> → gera evento de saída + evento de recebimento interno.</li>
     *   <li><b>Poupança</b> → debita e registra rendimento projetado.</li>
     *   <li><b>Empréstimo</b> → credita com taxa de juros registrada.</li>
     * </ul>
     *
     * <p>Um evento pode ter <b>múltiplas instituições</b> (ex.: compra paga metade no débito,
     * metade no Pix) e <b>múltiplas categorias</b> (ex.: iFood → "Aplicativo" + "Alimentação").
     */
    public Registro createEventoFinanceiro(EventoFinanceiro financeiro,
                                           List<EventoInstituicao> instituicoes,
                                           EventoDetalhe detalhe) {
        // Valida e vincula o usuário real ao evento
        Usuario usuario = buscarUsuarioOuErro(financeiro.getUsuario().getId());
        financeiro.setUsuario(usuario);

        // Aplica as regras de negócio do tipo de evento via Strategy
        EventoFinanceiroStrategy strategy = eventoFinanceiroFactory.getStrategy(financeiro.getTipo());
        Registro registroProcessado = strategy.processar(financeiro, instituicoes, detalhe);

        // Persiste todos os eventos gerados pela strategy (pode ser 1 ou mais)
        return persistirRegistro(registroProcessado);
    }

    /**
     * Cria uma série de eventos recorrentes a partir de uma regra de recorrência.
     *
     * <p>Cada ocorrência recebe as mesmas instituições e o mesmo detalhe da requisição original.
     * Exemplo de uso: "Todo dia 15 recebo meu salário" ou "Todo dia compro almoço".
     *
     * @param recorrencia regra com periodicidade, datas e dados do evento.
     * @param instituicoes meios de pagamento (já mapeados do DTO).
     * @param detalhe título e categorias (já mapeados do DTO).
     */
    public List<RegistroResponseDto> createEventosRecorrentes(RecorrenciaFinanceira recorrencia,
                                                               List<EventoInstituicao> instituicoes,
                                                               EventoDetalhe detalhe) {
        Usuario usuario = buscarUsuarioOuErro(recorrencia.getUsuario().getId());
        recorrencia.setUsuario(usuario);

        RecorrenciaStrategy strategy = recorrenciaFactory.getStrategy(recorrencia.getPeriodicidade());
        List<EventoFinanceiro> eventosGerados = strategy.gerarEventos(recorrencia, recorrencia.getDataFim());

        return eventosGerados.stream()
                .map(evento -> {
                    evento.setDataRegistro(LocalDateTime.now());
                    EventoFinanceiro salvo         = eventoFinanceiroRepository.save(evento);
                    List<EventoInstituicao> insts  = createEventoInstituicao(instituicoes, salvo);
                    EventoDetalhe detalheSalvo     = createGastoDetalhe(detalhe, salvo);
                    return RegistrosMapper.toResponse(salvo, insts, detalheSalvo);
                })
                .toList();
    }

    /**
     * Valida e persiste os meios de pagamento de um evento.
     *
     * <p>Regras aplicadas por tipo de movimento:
     * <ul>
     *   <li><b>Débito / Pix / Dinheiro</b> → pagamento à vista (1 parcela).</li>
     *   <li><b>Voucher</b> → pagamento à vista; apenas instituições aceitas pelo tipo.</li>
     *   <li><b>Crédito / Boleto</b> → parcelado; cria um {@link EventoInstituicao} por parcela.</li>
     * </ul>
     * Para Gasto e Transferência, verifica se há saldo suficiente na instituição.
     */
    public List<EventoInstituicao> createEventoInstituicao(List<EventoInstituicao> instituicoes,
                                                            EventoFinanceiro evento) {
        if (!eventoFinanceiroRepository.existsById(evento.getId())) {
            throw new EntidadeNaoEncontradaException(
                    "Evento Financeiro de id: %s não encontrado.".formatted(evento.getId()));
        }

        // Cada instituição pode gerar 1 ou N registros (parcelamento)
        return instituicoes.stream()
                .flatMap(inst -> processarPagamento(inst, evento).stream())
                .toList();
    }

    /**
     * Valida e persiste o detalhe de um evento (título + categorias).
     *
     * <p>Um evento pode ter <b>múltiplas categorias</b> — por exemplo, um pedido no iFood
     * pode ser categorizado como "Aplicativo" e "Alimentação" ao mesmo tempo.
     */
    public EventoDetalhe createGastoDetalhe(EventoDetalhe detalhe, EventoFinanceiro evento) {
        if (!eventoFinanceiroRepository.existsById(evento.getId())) {
            throw new EntidadeNaoEncontradaException(
                    "Evento Financeiro de id: %s não encontrado.".formatted(evento.getId()));
        }

        // Verifica se todas as categorias existem antes de salvar
        List<CategoriaUsuario> categorias = detalhe.getCategoriaUsuario().stream()
                .map(cu -> buscarCategoriaOuErro(cu.getId()))
                .toList();

        detalhe.setEventoFinanceiro(evento);
        detalhe.setCategoriaUsuario(categorias);
        return eventoDetalheRepository.save(detalhe);
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    /**
     * Atualiza os campos básicos de um evento: tipo, data e descrição.
     */
    public EventoFinanceiro editEventoFinanceiro(UUID eventoId, EventoFinanceiro novosDados) {
        EventoFinanceiro existente = buscarEventoOuErro(eventoId);

        if (!novosDados.getDataEvento().equals(existente.getDataEvento())) {
            existente.setDataEvento(novosDados.getDataEvento());
        }
        if (!Objects.equals(novosDados.getDescricao(), existente.getDescricao())) {
            existente.setDescricao(novosDados.getDescricao());
        }
        if (novosDados.getTipo() != existente.getTipo()) {
            existente.setTipo(novosDados.getTipo());
        }
        return eventoFinanceiroRepository.save(existente);
    }

    /**
     * Sincroniza os meios de pagamento de um evento com a nova lista recebida.
     * Remove os que saíram, atualiza os que ficaram e cria os novos.
     */
    public List<EventoInstituicao> editEventoInstituicao(UUID eventoId, List<EventoInstituicao> novas) {
        EventoFinanceiro evento = buscarEventoOuErro(eventoId);

        List<EventoInstituicao> existentes = eventoInstituicaoRepository
                .findEventoInstituicaoByEventoFinanceiro_Id(eventoId);

        // IDs que vieram na nova lista
        Set<Integer> novosIds = novas.stream()
                .map(e -> e.getInstituicaoUsuario().getId())
                .collect(Collectors.toSet());

        // Remove as que não estão mais na lista
        existentes.stream()
                .filter(ex -> !novosIds.contains(ex.getInstituicaoUsuario().getId()))
                .forEach(eventoInstituicaoRepository::delete);

        // Atualiza ou insere cada item da nova lista
        return novas.stream().map(nova -> {
            EventoInstituicao alvo = existentes.stream()
                    .filter(ex -> Objects.equals(ex.getInstituicaoUsuario().getId(),
                            nova.getInstituicaoUsuario().getId()))
                    .findFirst()
                    .orElse(new EventoInstituicao());

            InstituicaoUsuario instUsuario = buscarInstituicaoAtivaOuErro(nova.getInstituicaoUsuario().getId());
            alvo.setInstituicaoUsuario(instUsuario);
            alvo.setValor(nova.getValor());
            alvo.setParcelas(nova.getParcelas());
            alvo.setTipoMovimento(nova.getTipoMovimento());
            alvo.setEventoFinanceiro(evento);
            return eventoInstituicaoRepository.save(alvo);
        }).toList();
    }

    /**
     * Atualiza título e categorias do detalhe de um evento.
     */
    public EventoDetalhe editGastoDetalhe(UUID eventoId, EventoDetalhe novosDados) {
        EventoFinanceiro evento = buscarEventoOuErro(eventoId);
        EventoDetalhe detalhe  = eventoDetalheRepository.findGastoDetalheByEventoFinanceiro_Id(eventoId);

        if (!Objects.equals(novosDados.getTituloGasto(), detalhe.getTituloGasto())) {
            detalhe.setTituloGasto(novosDados.getTituloGasto());
        }

        // Sincroniza categorias: remove as que saíram, adiciona as novas
        Set<Integer> novosIds = novosDados.getCategoriaUsuario().stream()
                .map(CategoriaUsuario::getId)
                .collect(Collectors.toSet());

        List<CategoriaUsuario> categoriasAtuais = new ArrayList<>(detalhe.getCategoriaUsuario());
        categoriasAtuais.removeIf(c -> !novosIds.contains(c.getId()));

        novosDados.getCategoriaUsuario().forEach(nova -> {
            boolean jaExiste = categoriasAtuais.stream().anyMatch(c -> Objects.equals(c.getId(), nova.getId()));
            if (!jaExiste) {
                categoriasAtuais.add(buscarCategoriaOuErro(nova.getId()));
            }
        });

        detalhe.setCategoriaUsuario(categoriasAtuais);
        detalhe.setEventoFinanceiro(evento);
        return eventoDetalheRepository.save(detalhe);
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    /**
     * Remove um registro completo. As sub-entidades (instituições e detalhe) são removidas
     * automaticamente pelo JPA via {@code CascadeType.ALL + orphanRemoval = true}.
     */
    public void deleteRegistroByEventoFinanceiro_Id(UUID eventoId) {
        EventoFinanceiro evento = buscarEventoOuErro(eventoId);
        eventoFinanceiroRepository.delete(evento);
    }

    // =========================================================================
    // PRIVADOS — persistência
    // =========================================================================

    /**
     * Percorre todos os eventos gerados pela Strategy, salva cada um e vincula
     * as respectivas instituições e detalhes.
     */
    private Registro persistirRegistro(Registro registroProcessado) {
        List<EventoFinanceiro> eventosSalvos             = new ArrayList<>();
        Map<EventoFinanceiro, List<EventoInstituicao>> instituicoesMap = new HashMap<>();
        Map<EventoFinanceiro, EventoDetalhe> detalheMap  = new HashMap<>();

        for (EventoFinanceiro ev : registroProcessado.getEventosFinanceiros()) {
            ev.setDataRegistro(LocalDateTime.now());
            EventoFinanceiro evSalvo = eventoFinanceiroRepository.save(ev);
            eventosSalvos.add(evSalvo);

            // Vincula meios de pagamento (pode ser mais de um)
            List<EventoInstituicao> insts = registroProcessado.getInstituicoesPorEvento().get(ev);
            if (insts != null) {
                instituicoesMap.put(evSalvo, createEventoInstituicao(insts, evSalvo));
            }

            // Vincula detalhe (título + categorias)
            EventoDetalhe det = registroProcessado.getDetalhePorEvento().get(ev);
            if (det != null) {
                detalheMap.put(evSalvo, createGastoDetalhe(det, evSalvo));
            }
        }

        return new Registro(eventosSalvos, instituicoesMap, detalheMap);
    }

    /**
     * Valida uma instituição, aplica as regras do tipo de movimento (Strategy),
     * confere o saldo quando necessário e persiste as parcelas.
     */
    private List<EventoInstituicao> processarPagamento(EventoInstituicao pagamento,
                                                        EventoFinanceiro evento) {
        InstituicaoUsuario instUsuario = buscarInstituicaoAtivaOuErro(pagamento.getInstituicaoUsuario().getId());

        Map<String, Object> params = Map.of("parcelas", pagamento.getParcelas());
        MovimentoStrategy movimentoStrategy = movimentoFactory.getStrategy(pagamento.getTipoMovimento(), params);
        movimentoStrategy.validar(instUsuario);
        MovimentoResultado resultado = movimentoStrategy.processar(pagamento);

        // Gastos e transferências requerem saldo suficiente na instituição
        if (tipoRequerValidacaoSaldo(evento.getTipo())) {
            BigDecimal saldoDisponivel = instituicaoService.getSaldoByInstituicao(instUsuario.getId());
            if (BigDecimal.valueOf(resultado.getValorParcela()).compareTo(saldoDisponivel) > 0) {
                throw new SaldoInsuficienteException(
                        "Saldo insuficiente na instituição %s para realizar a operação."
                                .formatted(instUsuario.getInstituicao().getNome()));
            }
        }

        return salvarParcelas(resultado, pagamento, instUsuario, evento);
    }

    /**
     * Salva os registros de parcelas de um pagamento.
     *
     * <ul>
     *   <li><b>À vista (1 parcela)</b>: salva um único {@link EventoInstituicao}.</li>
     *   <li><b>Parcelado (N parcelas)</b>: salva um registro por parcela com o valor fracionado.
     *       Ex.: R$ 300 em 3x → três registros de R$ 100.</li>
     * </ul>
     */
    private List<EventoInstituicao> salvarParcelas(MovimentoResultado resultado,
                                                    EventoInstituicao pagamento,
                                                    InstituicaoUsuario instUsuario,
                                                    EventoFinanceiro evento) {
        if (resultado.getParcelas() == 1) {
            pagamento.setInstituicaoUsuario(instUsuario);
            pagamento.setEventoFinanceiro(evento);
            pagamento.setParcelas(1);
            return List.of(eventoInstituicaoRepository.save(pagamento));
        }

        // Parcelado: cria um registro por número de parcela
        return IntStream.rangeClosed(1, resultado.getParcelas())
                .mapToObj(numeroParcela -> {
                    EventoInstituicao parcela = new EventoInstituicao();
                    parcela.setParcelas(numeroParcela);
                    parcela.setEventoFinanceiro(evento);
                    parcela.setInstituicaoUsuario(instUsuario);
                    parcela.setTipoMovimento(pagamento.getTipoMovimento());
                    parcela.setValor(resultado.getValorParcela());
                    return eventoInstituicaoRepository.save(parcela);
                })
                .toList();
    }

    // =========================================================================
    // PRIVADOS — validação e busca
    // =========================================================================

    /**
     * Tipos que exigem verificação de saldo antes de processar o pagamento.
     * Recebimento, Poupança e Empréstimo são entradas — não consomem saldo.
     */
    private boolean tipoRequerValidacaoSaldo(Tipo tipo) {
        return tipo == Tipo.Gasto || tipo == Tipo.Transferencia;
    }

    private Usuario buscarUsuarioOuErro(UUID id) {
        return usuarioRepository.findById(id)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Usuário de id: %s não encontrado.".formatted(id)));
    }

    private EventoFinanceiro buscarEventoOuErro(UUID eventoId) {
        return eventoFinanceiroRepository.findById(eventoId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Evento financeiro de id: %s não encontrado.".formatted(eventoId)));
    }

    /** Busca e valida que a instituição existe e está ativa. */
    private InstituicaoUsuario buscarInstituicaoAtivaOuErro(Integer id) {
        InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(id)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Instituição associada ao usuário não encontrada."));
        if (!inst.getIsAtivo()) {
            throw new InstituicaoInativaException(
                    "Instituição '%s' está inativa e não pode ser utilizada."
                            .formatted(inst.getInstituicao().getNome()));
        }
        return inst;
    }

    private CategoriaUsuario buscarCategoriaOuErro(Integer id) {
        return categoriaUsuarioRepository.findById(id)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Categoria Usuário de id: %d não encontrada.".formatted(id)));
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.registros.mapper.RegistrosMapper;
import controle.api.back_end.dto.registros.out.RegistroResponseDto;
import controle.api.back_end.exception.EntidadeNaoEncontradaException;
import controle.api.back_end.exception.InstituicaoInativaException;
import controle.api.back_end.exception.SaldoInsuficienteException;
import controle.api.back_end.factory.EventoFinanceiroFactory;
import controle.api.back_end.factory.MovimentoFactory;
import controle.api.back_end.factory.RecorrenciaFactory;
import controle.api.back_end.model.categoria.CategoriaUsuario;
import controle.api.back_end.model.eventoFinanceiro.*;
import controle.api.back_end.model.eventoFinanceiro.recorrenciaFinanceira.RecorrenciaFinanceira;
import controle.api.back_end.model.instituicao.InstituicaoUsuario;
import controle.api.back_end.model.usuario.Usuario;
import controle.api.back_end.repository.categoria.CategoriaUsuarioRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoDetalheRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoInstituicaoRepository;
import controle.api.back_end.repository.instituicao.InstituicaoUsuarioRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import controle.api.back_end.specifications.EventoFinanceiroSpecifications;
import controle.api.back_end.strategy.eventoFinanceiro.EventoFinanceiroStrategy;
import controle.api.back_end.strategy.eventoFinanceiro.Registro;
import controle.api.back_end.strategy.movimento.MovimentoResultado;
import controle.api.back_end.strategy.movimento.MovimentoStrategy;
import controle.api.back_end.strategy.recorrenciaFinanceira.RecorrenciaStrategy;
import controle.api.back_end.model.configuracoes.TipoAlertaEmail;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.jpa.domain.Specification;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;
import java.util.stream.IntStream;
import java.util.Locale;

/**
 * Serviço principal de registros financeiros.
 *
 * <p>Responsabilidades:
 * <ul>
 *   <li>Consultar registros do usuário (com ou sem filtros)</li>
 *   <li>Criar eventos únicos, em lote ou recorrentes</li>
 *   <li>Editar eventos já existentes</li>
 *   <li>Excluir eventos</li>
 * </ul>
 *
 * <p>Exportação de arquivos (JSON, SQL, Excel, PDF) é responsabilidade de
 * {@link RegistroExportacaoService}.
 */
@Service
@Transactional
public class RegistroService {

    private static final Logger log = LoggerFactory.getLogger(RegistroService.class);

    // Ordem de exibição dos tipos: Recebimento → Gasto → Transferencia → Poupanca → Emprestimo
    private static final Map<Tipo, Integer> TIPO_ORDEM = Map.of(
            Tipo.Recebimento, 0,
            Tipo.Gasto, 1,
            Tipo.Transferencia, 2,
            Tipo.Poupanca, 3,
            Tipo.Emprestimo, 4
    );
    private static final int REGISTROS_POR_PAGINA_PADRAO = 20;
    private static final int REGISTROS_POR_PAGINA_MINIMO  = 5;
    private static final int REGISTROS_POR_PAGINA_MAXIMO  = 100;

    private final EventoFinanceiroRepository eventoFinanceiroRepository;
    private final EventoInstituicaoRepository eventoInstituicaoRepository;
    private final EventoDetalheRepository eventoDetalheRepository;
    private final CategoriaUsuarioRepository categoriaUsuarioRepository;
    private final UsuarioRepository usuarioRepository;
    private final InstituicaoUsuarioRepository instituicaoUsuarioRepository;
    private final MovimentoFactory movimentoFactory;
    private final EventoFinanceiroFactory eventoFinanceiroFactory;
    private final RecorrenciaFactory recorrenciaFactory;
    private final InstituicaoService instituicaoService;
    private final ConfiguracoesRepository configuracoesRepository;
    private final EmailService emailService;

    public RegistroService(EventoFinanceiroRepository eventoFinanceiroRepository,
                           EventoInstituicaoRepository eventoInstituicaoRepository,
                           EventoDetalheRepository eventoDetalheRepository,
                           CategoriaUsuarioRepository categoriaUsuarioRepository,
                           UsuarioRepository usuarioRepository,
                           InstituicaoUsuarioRepository instituicaoUsuarioRepository,
                           MovimentoFactory movimentoFactory,
                           EventoFinanceiroFactory eventoFinanceiroFactory,
                           RecorrenciaFactory recorrenciaFactory,
                           InstituicaoService instituicaoService,
                           ConfiguracoesRepository configuracoesRepository,
                           EmailService emailService) {
        this.eventoFinanceiroRepository  = eventoFinanceiroRepository;
        this.eventoInstituicaoRepository = eventoInstituicaoRepository;
        this.eventoDetalheRepository     = eventoDetalheRepository;
        this.categoriaUsuarioRepository  = categoriaUsuarioRepository;
        this.usuarioRepository           = usuarioRepository;
        this.instituicaoUsuarioRepository = instituicaoUsuarioRepository;
        this.movimentoFactory            = movimentoFactory;
        this.eventoFinanceiroFactory     = eventoFinanceiroFactory;
        this.recorrenciaFactory          = recorrenciaFactory;
        this.instituicaoService          = instituicaoService;
        this.configuracoesRepository     = configuracoesRepository;
        this.emailService                = emailService;
    }

    // =========================================================================
    // CONSULTAS
    // =========================================================================

    /**
     * Retorna todos os eventos financeiros do usuário, ordenados por data.
     */
    @Transactional(readOnly = true)
    public List<EventoFinanceiro> getEventosFinanceirosByUser(UUID userId) {
        if (!usuarioRepository.existsById(userId)) {
            throw new EntidadeNaoEncontradaException("Usuário de id: %s não encontrado.".formatted(userId));
        }
        return eventoFinanceiroRepository.getEventoFinanceirosByUsuario_id(userId);
    }

    /**
     * Para cada evento da lista, retorna suas instituições vinculadas (mesma ordem).
     */
    @Transactional(readOnly = true)
    public List<List<EventoInstituicao>> getEventosInstituicoesByEventoFinanceiro(List<EventoFinanceiro> eventos) {
        return eventos.stream()
                .map(ev -> eventoInstituicaoRepository.findEventoInstituicaoByEventoFinanceiro_Id(ev.getId()))
                .toList();
    }

    /**
     * Para cada evento da lista, retorna seu detalhe (título + categorias) (mesma ordem).
     */
    @Transactional(readOnly = true)
    public List<EventoDetalhe> getGastosDetalhesByEventoFinanceiro(List<EventoFinanceiro> eventos) {
        return eventos.stream()
                .map(ev -> {
                    if (!eventoFinanceiroRepository.existsById(ev.getId())) {
                        throw new EntidadeNaoEncontradaException(
                                "Evento financeiro de id: %s não encontrado.".formatted(ev.getId()));
                    }
                    return eventoDetalheRepository.findGastoDetalheByEventoFinanceiro(ev);
                })
                .toList();
    }

    /**
     * Retorna o saldo acumulado na poupança do usuário.
     */
    @Transactional(readOnly = true)
    public Double getSaldoPoupanca(UUID userId) {
        buscarUsuarioOuErro(userId); // valida existência
        // TODO: implementar cálculo real com base nos eventos de poupança
        return 0.0;
    }

    /**
     * Retorna os anos distintos em que o usuário possui registros (mais recente primeiro).
     */
    @Transactional(readOnly = true)
    public List<Integer> getAnosByUserId(UUID userId) {
        buscarUsuarioOuErro(userId);
        return eventoFinanceiroRepository.findDistinctAnosByUserId(userId);
    }

    /**
     * Retorna os meses distintos em que o usuário possui registros no ano informado (1–12).
     */
    @Transactional(readOnly = true)
    public List<Integer> getMesesByUserIdAndAno(UUID userId, int ano) {
        buscarUsuarioOuErro(userId);
        return eventoFinanceiroRepository.findDistinctMesesByUserIdAndAno(userId, ano);
    }

    /**
     * Retorna os registros do mês/ano de forma paginada,
     * ordenados por: dia ASC → tipo (Recebimento primeiro) → título ASC.
     *
     * @param tamanho itens por página; limitado entre {@value #REGISTROS_POR_PAGINA_MINIMO}
     *                e {@value #REGISTROS_POR_PAGINA_MAXIMO}. Padrão: {@value #REGISTROS_POR_PAGINA_PADRAO}.
     */
    @Transactional(readOnly = true)
    public Page<RegistroResponseDto> getRegistrosByMes(UUID userId, int ano, int mes, int pagina, int tamanho) {
        buscarUsuarioOuErro(userId);

        // Garante que o tamanho esteja dentro dos limites permitidos
        int tamanhoPagina = Math.max(REGISTROS_POR_PAGINA_MINIMO,
                            Math.min(tamanho, REGISTROS_POR_PAGINA_MAXIMO));

        // Busca todos os eventos do mês com EventoDetalhe pré-carregado via JOIN FETCH
        List<EventoFinanceiro> todos =
                eventoFinanceiroRepository.findByUserIdAndAnoAndMes(userId, ano, mes);

        // Ordena: dia → tipo customizado → título alfabético
        List<EventoFinanceiro> ordenados = todos.stream()
                .sorted(Comparator
                        .comparing(EventoFinanceiro::getDataEvento)
                        .thenComparingInt(e -> TIPO_ORDEM.getOrDefault(e.getTipo(), 99))
                        .thenComparing(e -> {
                            EventoDetalhe d = e.getGastoDetalhe();
                            return (d != null && d.getTituloGasto() != null)
                                    ? d.getTituloGasto().toLowerCase(Locale.ROOT) : "";
                        }))
                .toList();

        int total = ordenados.size();
        int start = pagina * tamanhoPagina;

        if (start >= total) {
            return new PageImpl<>(List.of(), PageRequest.of(pagina, tamanhoPagina), total);
        }

        int end = Math.min(start + tamanhoPagina, total);

        // Mapeia apenas os itens da página atual — instituicoes são lazy mas a sessão está aberta
        List<RegistroResponseDto> dtos = ordenados.subList(start, end).stream()
                .map(ev -> RegistrosMapper.toResponse(ev, ev.getEventoInstituicoes(), ev.getGastoDetalhe()))
                .filter(Objects::nonNull)
                .toList();

        return new PageImpl<>(dtos, PageRequest.of(pagina, tamanhoPagina), total);
    }

    /**
     * Busca registros aplicando filtros dinâmicos. Todos os parâmetros são opcionais.
     */
    @Transactional(readOnly = true)
    public List<RegistroResponseDto> getByFilter(UUID userId,
                                                  Double valor,
                                                  List<TipoMovimento> tiposMovimento,
                                                  List<Tipo> tipos,
                                                  LocalDate dataEvento,
                                                  List<InstituicaoUsuario> instituicoes,
                                                  List<CategoriaUsuario> categorias,
                                                  String descricao,
                                                  String titulo) {
        Usuario usuario = buscarUsuarioOuErro(userId);

        Specification<EventoFinanceiro> filtroUsuario =
                (root, query, cb) -> cb.equal(root.get("usuario"), usuario);

        Specification<EventoFinanceiro> filtros = EventoFinanceiroSpecifications.porFiltros(
                valor, tipos, dataEvento, descricao, tiposMovimento, instituicoes, categorias, titulo);

        return eventoFinanceiroRepository.findAll(filtroUsuario.and(filtros)).stream()
                .map(ev -> RegistrosMapper.toResponse(ev, ev.getEventoInstituicoes(), ev.getGastoDetalhe()))
                .collect(Collectors.toList());
    }

    // =========================================================================
    // CRIAR
    // =========================================================================

    /**
     * Cria um registro financeiro completo (evento + meios de pagamento + detalhe).
     *
     * <p>As regras de cada tipo são aplicadas via Strategy:
     * <ul>
     *   <li><b>Gasto</b> → debita da(s) instituição(ões); valida saldo.</li>
     *   <li><b>Recebimento</b> → credita na(s) instituição(ões).</li>
     *   <li><b>Transferência</b> → gera evento de saída + evento de recebimento interno.</li>
     *   <li><b>Poupança</b> → debita e registra rendimento projetado.</li>
     *   <li><b>Empréstimo</b> → credita com taxa de juros registrada.</li>
     * </ul>
     *
     * <p>Um evento pode ter <b>múltiplas instituições</b> (ex.: compra paga metade no débito,
     * metade no Pix) e <b>múltiplas categorias</b> (ex.: iFood → "Aplicativo" + "Alimentação").
     */
    public Registro createEventoFinanceiro(EventoFinanceiro financeiro,
                                           List<EventoInstituicao> instituicoes,
                                           EventoDetalhe detalhe) {
        // Valida e vincula o usuário real ao evento
        Usuario usuario = buscarUsuarioOuErro(financeiro.getUsuario().getId());
        financeiro.setUsuario(usuario);

        // Aplica as regras de negócio do tipo de evento via Strategy
        EventoFinanceiroStrategy strategy = eventoFinanceiroFactory.getStrategy(financeiro.getTipo());
        Registro registroProcessado = strategy.processar(financeiro, instituicoes, detalhe);

        // Persiste todos os eventos gerados pela strategy (pode ser 1 ou mais)
        return persistirRegistro(registroProcessado);
    }

    /**
     * Cria uma série de eventos recorrentes a partir de uma regra de recorrência.
     *
     * <p>Cada ocorrência recebe as mesmas instituições e o mesmo detalhe da requisição original.
     * Exemplo de uso: "Todo dia 15 recebo meu salário" ou "Todo dia compro almoço".
     *
     * @param recorrencia regra com periodicidade, datas e dados do evento.
     * @param instituicoes meios de pagamento (já mapeados do DTO).
     * @param detalhe título e categorias (já mapeados do DTO).
     */
    public List<RegistroResponseDto> createEventosRecorrentes(RecorrenciaFinanceira recorrencia,
                                                               List<EventoInstituicao> instituicoes,
                                                               EventoDetalhe detalhe) {
        Usuario usuario = buscarUsuarioOuErro(recorrencia.getUsuario().getId());
        recorrencia.setUsuario(usuario);

        RecorrenciaStrategy strategy = recorrenciaFactory.getStrategy(recorrencia.getPeriodicidade());
        List<EventoFinanceiro> eventosGerados = strategy.gerarEventos(recorrencia, recorrencia.getDataFim());

        return eventosGerados.stream()
                .map(evento -> {
                    evento.setDataRegistro(LocalDateTime.now());
                    EventoFinanceiro salvo         = eventoFinanceiroRepository.save(evento);
                    List<EventoInstituicao> insts  = createEventoInstituicao(instituicoes, salvo);
                    EventoDetalhe detalheSalvo     = createGastoDetalhe(detalhe, salvo);
                    return RegistrosMapper.toResponse(salvo, insts, detalheSalvo);
                })
                .toList();
    }

    /**
     * Valida e persiste os meios de pagamento de um evento.
     *
     * <p>Regras aplicadas por tipo de movimento:
     * <ul>
     *   <li><b>Débito / Pix / Dinheiro</b> → pagamento à vista (1 parcela).</li>
     *   <li><b>Voucher</b> → pagamento à vista; apenas instituições aceitas pelo tipo.</li>
     *   <li><b>Crédito / Boleto</b> → parcelado; cria um {@link EventoInstituicao} por parcela.</li>
     * </ul>
     * Para Gasto e Transferência, verifica se há saldo suficiente na instituição.
     */
    public List<EventoInstituicao> createEventoInstituicao(List<EventoInstituicao> instituicoes,
                                                            EventoFinanceiro evento) {
        if (!eventoFinanceiroRepository.existsById(evento.getId())) {
            throw new EntidadeNaoEncontradaException(
                    "Evento Financeiro de id: %s não encontrado.".formatted(evento.getId()));
        }

        // Cada instituição pode gerar 1 ou N registros (parcelamento)
        return instituicoes.stream()
                .flatMap(inst -> processarPagamento(inst, evento).stream())
                .toList();
    }

    /**
     * Valida e persiste o detalhe de um evento (título + categorias).
     *
     * <p>Um evento pode ter <b>múltiplas categorias</b> — por exemplo, um pedido no iFood
     * pode ser categorizado como "Aplicativo" e "Alimentação" ao mesmo tempo.
     */
    public EventoDetalhe createGastoDetalhe(EventoDetalhe detalhe, EventoFinanceiro evento) {
        if (!eventoFinanceiroRepository.existsById(evento.getId())) {
            throw new EntidadeNaoEncontradaException(
                    "Evento Financeiro de id: %s não encontrado.".formatted(evento.getId()));
        }

        // Verifica se todas as categorias existem antes de salvar
        List<CategoriaUsuario> categorias = detalhe.getCategoriaUsuario().stream()
                .map(cu -> buscarCategoriaOuErro(cu.getId()))
                .toList();

        detalhe.setEventoFinanceiro(evento);
        detalhe.setCategoriaUsuario(categorias);
        return eventoDetalheRepository.save(detalhe);
    }

    // =========================================================================
    // EDITAR
    // =========================================================================

    /**
     * Atualiza os campos básicos de um evento: tipo, data e descrição.
     */
    public EventoFinanceiro editEventoFinanceiro(UUID eventoId, EventoFinanceiro novosDados) {
        EventoFinanceiro existente = buscarEventoOuErro(eventoId);

        if (!novosDados.getDataEvento().equals(existente.getDataEvento())) {
            existente.setDataEvento(novosDados.getDataEvento());
        }
        if (!Objects.equals(novosDados.getDescricao(), existente.getDescricao())) {
            existente.setDescricao(novosDados.getDescricao());
        }
        if (novosDados.getTipo() != existente.getTipo()) {
            existente.setTipo(novosDados.getTipo());
        }
        return eventoFinanceiroRepository.save(existente);
    }

    /**
     * Sincroniza os meios de pagamento de um evento com a nova lista recebida.
     * Remove os que saíram, atualiza os que ficaram e cria os novos.
     */
    public List<EventoInstituicao> editEventoInstituicao(UUID eventoId, List<EventoInstituicao> novas) {
        EventoFinanceiro evento = buscarEventoOuErro(eventoId);

        List<EventoInstituicao> existentes = eventoInstituicaoRepository
                .findEventoInstituicaoByEventoFinanceiro_Id(eventoId);

        // IDs que vieram na nova lista
        Set<Integer> novosIds = novas.stream()
                .map(e -> e.getInstituicaoUsuario().getId())
                .collect(Collectors.toSet());

        // Remove as que não estão mais na lista
        existentes.stream()
                .filter(ex -> !novosIds.contains(ex.getInstituicaoUsuario().getId()))
                .forEach(eventoInstituicaoRepository::delete);

        // Atualiza ou insere cada item da nova lista
        return novas.stream().map(nova -> {
            EventoInstituicao alvo = existentes.stream()
                    .filter(ex -> Objects.equals(ex.getInstituicaoUsuario().getId(),
                            nova.getInstituicaoUsuario().getId()))
                    .findFirst()
                    .orElse(new EventoInstituicao());

            InstituicaoUsuario instUsuario = buscarInstituicaoAtivaOuErro(nova.getInstituicaoUsuario().getId());
            alvo.setInstituicaoUsuario(instUsuario);
            alvo.setValor(nova.getValor());
            alvo.setParcelas(nova.getParcelas());
            alvo.setTipoMovimento(nova.getTipoMovimento());
            alvo.setEventoFinanceiro(evento);
            return eventoInstituicaoRepository.save(alvo);
        }).toList();
    }

    /**
     * Atualiza título e categorias do detalhe de um evento.
     */
    public EventoDetalhe editGastoDetalhe(UUID eventoId, EventoDetalhe novosDados) {
        EventoFinanceiro evento = buscarEventoOuErro(eventoId);
        EventoDetalhe detalhe  = eventoDetalheRepository.findGastoDetalheByEventoFinanceiro_Id(eventoId);

        if (!Objects.equals(novosDados.getTituloGasto(), detalhe.getTituloGasto())) {
            detalhe.setTituloGasto(novosDados.getTituloGasto());
        }

        // Sincroniza categorias: remove as que saíram, adiciona as novas
        Set<Integer> novosIds = novosDados.getCategoriaUsuario().stream()
                .map(CategoriaUsuario::getId)
                .collect(Collectors.toSet());

        List<CategoriaUsuario> categoriasAtuais = new ArrayList<>(detalhe.getCategoriaUsuario());
        categoriasAtuais.removeIf(c -> !novosIds.contains(c.getId()));

        novosDados.getCategoriaUsuario().forEach(nova -> {
            boolean jaExiste = categoriasAtuais.stream().anyMatch(c -> Objects.equals(c.getId(), nova.getId()));
            if (!jaExiste) {
                categoriasAtuais.add(buscarCategoriaOuErro(nova.getId()));
            }
        });

        detalhe.setCategoriaUsuario(categoriasAtuais);
        detalhe.setEventoFinanceiro(evento);
        return eventoDetalheRepository.save(detalhe);
    }

    // =========================================================================
    // DELETAR
    // =========================================================================

    /**
     * Remove um registro completo. As sub-entidades (instituições e detalhe) são removidas
     * automaticamente pelo JPA via {@code CascadeType.ALL + orphanRemoval = true}.
     */
    public void deleteRegistroByEventoFinanceiro_Id(UUID eventoId) {
        EventoFinanceiro evento = buscarEventoOuErro(eventoId);
        eventoFinanceiroRepository.delete(evento);
    }

    // =========================================================================
    // PRIVADOS — persistência
    // =========================================================================

    /**
     * Percorre todos os eventos gerados pela Strategy, salva cada um e vincula
     * as respectivas instituições e detalhes.
     */
    private Registro persistirRegistro(Registro registroProcessado) {
        List<EventoFinanceiro> eventosSalvos             = new ArrayList<>();
        Map<EventoFinanceiro, List<EventoInstituicao>> instituicoesMap = new HashMap<>();
        Map<EventoFinanceiro, EventoDetalhe> detalheMap  = new HashMap<>();

        for (EventoFinanceiro ev : registroProcessado.getEventosFinanceiros()) {
            ev.setDataRegistro(LocalDateTime.now());
            EventoFinanceiro evSalvo = eventoFinanceiroRepository.save(ev);
            eventosSalvos.add(evSalvo);

            // Vincula meios de pagamento (pode ser mais de um)
            List<EventoInstituicao> insts = registroProcessado.getInstituicoesPorEvento().get(ev);
            if (insts != null) {
                instituicoesMap.put(evSalvo, createEventoInstituicao(insts, evSalvo));
            }

            // Vincula detalhe (título + categorias)
            EventoDetalhe det = registroProcessado.getDetalhePorEvento().get(ev);
            if (det != null) {
                detalheMap.put(evSalvo, createGastoDetalhe(det, evSalvo));
            }
        }

        Registro resultado = new Registro(eventosSalvos, instituicoesMap, detalheMap);

        // Verifica alerta de limite mensal apos salvar
        eventosSalvos.stream()
                .filter(ev -> ev.getTipo() == Tipo.Gasto)
                .findFirst()
                .ifPresent(ev -> verificarEEnviarAlertaLimite(ev.getUsuario()));

        return resultado;
    }

    /**
     * Verifica se o gasto mensal do usuario cruzou o percentual de alerta configurado
     * e, se sim, envia o e-mail de alerta (uma vez por mes por usuario).
     */
    private void verificarEEnviarAlertaLimite(Usuario usuario) {
        try {
            configuracoesRepository.findConfiguracoesByUsuario_Id(usuario.getId())
                    .ifPresent(config -> {
                        if (!config.getAlertasEmailAtivos().contains(TipoAlertaEmail.ALERTA_LIMITE_MENSAL)) return;
                        if (config.getLimiteDesejadoMensal() == null || config.getLimiteDesejadoMensal() <= 0) return;

                        // Ja enviou alerta este mes?
                        LocalDate hoje = LocalDate.now();
                        if (config.getUltimoAlertaGastoEnviado() != null
                                && config.getUltimoAlertaGastoEnviado().getMonth() == hoje.getMonth()
                                && config.getUltimoAlertaGastoEnviado().getYear() == hoje.getYear()) {
                            return;
                        }

                        // Soma os gastos do mes atual
                        LocalDate inicioMes = hoje.withDayOfMonth(1);
                        double gastoMes = eventoFinanceiroRepository
                                .findEventoFinanceiroByUsuario_IdAndDataEventoBetween(
                                        usuario.getId(), inicioMes, hoje)
                                .stream()
                                .filter(e -> e.getTipo() == Tipo.Gasto)
                                .mapToDouble(EventoFinanceiro::getValor)
                                .sum();

                        double limite = config.getLimiteDesejadoMensal();
                        double percentualReal = (gastoMes / limite) * 100.0;
                        int threshold = config.getPercentualAlertaGasto() != null
                                ? config.getPercentualAlertaGasto() : 80;

                        if (percentualReal >= threshold) {
                            emailService.enviarAlertaLimiteMensal(
                                    usuario, gastoMes, limite, threshold, percentualReal);
                            config.setUltimoAlertaGastoEnviado(hoje);
                            configuracoesRepository.save(config);
                        }
                    });
        } catch (Exception e) {
            log.warn("[RegistroService] Erro ao verificar alerta de limite: {}", e.getMessage());
        }
    }

    /**
     * Valida uma instituição, aplica as regras do tipo de movimento (Strategy),
     * confere o saldo quando necessário e persiste as parcelas.
     */
    private List<EventoInstituicao> processarPagamento(EventoInstituicao pagamento,
                                                        EventoFinanceiro evento) {
        InstituicaoUsuario instUsuario = buscarInstituicaoAtivaOuErro(pagamento.getInstituicaoUsuario().getId());

        Map<String, Object> params = Map.of("parcelas", pagamento.getParcelas());
        MovimentoStrategy movimentoStrategy = movimentoFactory.getStrategy(pagamento.getTipoMovimento(), params);
        movimentoStrategy.validar(instUsuario);
        MovimentoResultado resultado = movimentoStrategy.processar(pagamento);

        // Gastos e transferências requerem saldo suficiente na instituição
        if (tipoRequerValidacaoSaldo(evento.getTipo())) {
            BigDecimal saldoDisponivel = instituicaoService.getSaldoByInstituicao(instUsuario.getId());
            if (BigDecimal.valueOf(resultado.getValorParcela()).compareTo(saldoDisponivel) > 0) {
                throw new SaldoInsuficienteException(
                        "Saldo insuficiente na instituição %s para realizar a operação."
                                .formatted(instUsuario.getInstituicao().getNome()));
            }
        }

        return salvarParcelas(resultado, pagamento, instUsuario, evento);
    }

    /**
     * Salva os registros de parcelas de um pagamento.
     *
     * <ul>
     *   <li><b>À vista (1 parcela)</b>: salva um único {@link EventoInstituicao}.</li>
     *   <li><b>Parcelado (N parcelas)</b>: salva um registro por parcela com o valor fracionado.
     *       Ex.: R$ 300 em 3x → três registros de R$ 100.</li>
     * </ul>
     */
    private List<EventoInstituicao> salvarParcelas(MovimentoResultado resultado,
                                                    EventoInstituicao pagamento,
                                                    InstituicaoUsuario instUsuario,
                                                    EventoFinanceiro evento) {
        if (resultado.getParcelas() == 1) {
            pagamento.setInstituicaoUsuario(instUsuario);
            pagamento.setEventoFinanceiro(evento);
            pagamento.setParcelas(1);
            return List.of(eventoInstituicaoRepository.save(pagamento));
        }

        // Parcelado: cria um registro por número de parcela
        return IntStream.rangeClosed(1, resultado.getParcelas())
                .mapToObj(numeroParcela -> {
                    EventoInstituicao parcela = new EventoInstituicao();
                    parcela.setParcelas(numeroParcela);
                    parcela.setEventoFinanceiro(evento);
                    parcela.setInstituicaoUsuario(instUsuario);
                    parcela.setTipoMovimento(pagamento.getTipoMovimento());
                    parcela.setValor(resultado.getValorParcela());
                    return eventoInstituicaoRepository.save(parcela);
                })
                .toList();
    }

    // =========================================================================
    // PRIVADOS — validação e busca
    // =========================================================================

    /**
     * Tipos que exigem verificação de saldo antes de processar o pagamento.
     * Recebimento, Poupança e Empréstimo são entradas — não consomem saldo.
     */
    private boolean tipoRequerValidacaoSaldo(Tipo tipo) {
        return tipo == Tipo.Gasto || tipo == Tipo.Transferencia;
    }

    private Usuario buscarUsuarioOuErro(UUID id) {
        return usuarioRepository.findById(id)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Usuário de id: %s não encontrado.".formatted(id)));
    }

    private EventoFinanceiro buscarEventoOuErro(UUID eventoId) {
        return eventoFinanceiroRepository.findById(eventoId)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Evento financeiro de id: %s não encontrado.".formatted(eventoId)));
    }

    /** Busca e valida que a instituição existe e está ativa. */
    private InstituicaoUsuario buscarInstituicaoAtivaOuErro(Integer id) {
        InstituicaoUsuario inst = instituicaoUsuarioRepository.findById(id)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Instituição associada ao usuário não encontrada."));
        if (!inst.getIsAtivo()) {
            throw new InstituicaoInativaException(
                    "Instituição '%s' está inativa e não pode ser utilizada."
                            .formatted(inst.getInstituicao().getNome()));
        }
        return inst;
    }

    private CategoriaUsuario buscarCategoriaOuErro(Integer id) {
        return categoriaUsuarioRepository.findById(id)
                .orElseThrow(() -> new EntidadeNaoEncontradaException(
                        "Categoria Usuário de id: %d não encontrada.".formatted(id)));
    }
}

package controle.api.back_end.service;

import controle.api.back_end.dto.poupanca.out.CaixinhaResponseDTO;
import controle.api.back_end.model.configuracoes.Configuracoes;
import controle.api.back_end.model.configuracoes.TipoAlertaEmail;
import controle.api.back_end.model.eventoFinanceiro.EventoFinanceiro;
import controle.api.back_end.model.eventoFinanceiro.Tipo;
import controle.api.back_end.model.usuario.Usuario;
import controle.api.back_end.repository.configuracoes.ConfiguracoesRepository;
import controle.api.back_end.repository.eventoFinanceiro.EventoFinanceiroRepository;
import controle.api.back_end.repository.poupanca.CaixinhaRepository;
import controle.api.back_end.repository.usuario.UsuarioRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

import java.time.LocalDate;
import java.util.List;

/**
 * Jobs agendados que disparam os e-mails automaticamente para os usuarios.
 *
 * <ul>
 *   <li>Aniversario        — diariamente as 08:00, verifica quem faz aniversario hoje.</li>
 *   <li>Relatorio mensal   — dia 1 de cada mes as 08:00.</li>
 *   <li>Lembrete de aporte — toda segunda-feira as 08:00.</li>
 * </ul>
 *
 * Os e-mails so sao enviados se o usuario tiver o tipo correspondente em
 * {@code Configuracoes.alertasEmailAtivos} e se {@code app.email.habilitado=true}.
 */
@Component
public class RelatorioEmailJob {

    private static final Logger log = LoggerFactory.getLogger(RelatorioEmailJob.class);

    private final ConfiguracoesRepository configuracoesRepository;
    private final CaixinhaRepository caixinhaRepository;
    private final CaixinhaService caixinhaService;
    private final EmailService emailService;
    private final UsuarioRepository usuarioRepository;
    private final EventoFinanceiroRepository eventoFinanceiroRepository;

    public RelatorioEmailJob(ConfiguracoesRepository configuracoesRepository,
                             CaixinhaRepository caixinhaRepository,
                             CaixinhaService caixinhaService,
                             EmailService emailService,
                             UsuarioRepository usuarioRepository,
                             EventoFinanceiroRepository eventoFinanceiroRepository) {
        this.configuracoesRepository    = configuracoesRepository;
        this.caixinhaRepository         = caixinhaRepository;
        this.caixinhaService            = caixinhaService;
        this.emailService               = emailService;
        this.usuarioRepository          = usuarioRepository;
        this.eventoFinanceiroRepository = eventoFinanceiroRepository;
    }

    // =========================================================================
    // ANIVERSARIO — todos os dias as 08:00
    // =========================================================================

    @Scheduled(cron = "0 0 8 * * *")
    public void dispararAniversario() {
        LocalDate hoje = LocalDate.now();
        log.info("[RelatorioEmailJob] Verificando aniversariantes de hoje ({}/{})...",
                hoje.getDayOfMonth(), hoje.getMonthValue());

        usuarioRepository.findAll().stream()
                .filter(u -> Boolean.TRUE.equals(u.getIsAtivo()))
                .filter(u -> u.getDataNascimento() != null
                          && u.getDataNascimento().getDayOfMonth() == hoje.getDayOfMonth()
                          && u.getDataNascimento().getMonthValue() == hoje.getMonthValue())
                .forEach(usuario -> {
                    // Verifica se o usuario ativou o alerta de aniversario
                    configuracoesRepository.findConfiguracoesByUsuario_Id(usuario.getId())
                            .ifPresent(config -> {
                                if (config.getAlertasEmailAtivos().contains(TipoAlertaEmail.ANIVERSARIO)) {
                                    emailService.enviarFelizAniversario(usuario);
                                    log.info("[RelatorioEmailJob] Feliz aniversario enviado para: {}",
                                            usuario.getEmail());
                                }
                            });
                });
    }

    // =========================================================================
    // RELATORIO MENSAL — dia 1 de cada mes as 08:00
    // =========================================================================

    @Scheduled(cron = "0 0 8 1 * *")
    public void dispararRelatorioMensal() {
        log.info("[RelatorioEmailJob] Disparando relatorios mensais...");

        configuracoesRepository.findAll().stream()
                .filter(c -> c.getAlertasEmailAtivos().contains(TipoAlertaEmail.RELATORIO_MENSAL))
                .forEach(config -> {
                    try {
                        Usuario usuario = config.getUsuario();

                        // Gastos do mes anterior
                        LocalDate inicioMesAnterior = LocalDate.now().minusMonths(1).withDayOfMonth(1);
                        LocalDate fimMesAnterior     = inicioMesAnterior.withDayOfMonth(
                                inicioMesAnterior.lengthOfMonth());

                        double gastoMes = eventoFinanceiroRepository
                                .findEventoFinanceiroByUsuario_IdAndDataEventoBetween(
                                        usuario.getId(), inicioMesAnterior, fimMesAnterior)
                                .stream()
                                .filter(e -> e.getTipo() == Tipo.Gasto)
                                .mapToDouble(EventoFinanceiro::getValor)
                                .sum();

                        List<CaixinhaResponseDTO> caixinhas = caixinhaRepository
                                .findAllByUsuario_IdAndIsAtivaTrue(usuario.getId())
                                .stream().map(caixinhaService::calcularEMontar).toList();

                        double limite = config.getLimiteDesejadoMensal() != null
                                ? config.getLimiteDesejadoMensal() : 0;

                        emailService.enviarRelatorioMensal(usuario, caixinhas, gastoMes, limite);
                    } catch (Exception e) {
                        log.error("[RelatorioEmailJob] Erro no relatorio mensal para usuario {}: {}",
                                config.getUsuario().getId(), e.getMessage());
                    }
                });
    }

    // =========================================================================
    // LEMBRETE DE APORTE — toda segunda-feira as 08:00
    // =========================================================================

    @Scheduled(cron = "0 0 8 * * MON")
    public void dispararLembreteSemanal() {
        log.info("[RelatorioEmailJob] Disparando lembretes semanais de aporte...");

        configuracoesRepository.findAll().stream()
                .filter(c -> c.getAlertasEmailAtivos().contains(TipoAlertaEmail.LEMBRETE_APORTE))
                .forEach(config -> {
                    try {
                        Usuario usuario = config.getUsuario();
                        List<CaixinhaResponseDTO> caixinhas = caixinhaRepository
                                .findAllByUsuario_IdAndIsAtivaTrue(usuario.getId())
                                .stream().map(caixinhaService::calcularEMontar).toList();

                        if (!caixinhas.isEmpty()) {
                            emailService.enviarLembreteAporte(usuario, caixinhas);
                        }
                    } catch (Exception e) {
                        log.error("[RelatorioEmailJob] Erro no lembrete semanal para usuario {}: {}",
                                config.getUsuario().getId(), e.getMessage());
                    }
                });
    }
}
